"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[662],{662:e=>{e.exports=JSON.parse('{"G":[{"id":1,"nome":"Estrutura\xe7\xe3o b\xe1sica para governan\xe7a","texto":"Este controle estabelece os pap\xe9is estruturantes da governan\xe7a em privacidade e seguran\xe7a\\nda informa\xe7\xe3o, destacando responsabilidades formais para a alta administra\xe7\xe3o, gestores e\\nrespons\xe1veis setoriais.","por_que_implementar":"A governan\xe7a em privacidade e seguran\xe7a da informa\xe7\xe3o depende da atua\xe7\xe3o de atores\\ninstitucionais com fun\xe7\xf5es bem delimitadas. A aus\xeancia de pap\xe9is claramente definidos pode\\ngerar riscos de lacunas de atua\xe7\xe3o, sobreposi\xe7\xe3o de fun\xe7\xf5es e perda de efetividade da\\ngovernan\xe7a. Esse controle assegura alinhamento estrat\xe9gico e operacional, al\xe9m de garantir\\nque a organiza\xe7\xe3o disponha de lideran\xe7as e agentes com atribui\xe7\xf5es definidas para conduzir\\nas a\xe7\xf5es do PPSI. O controle visa garantir que a alta administra\xe7\xe3o, gestores e respons\xe1veis\\nsetoriais atuem de maneira articulada e responsiva \xe0s exig\xeancias legais e regulat\xf3rias.","procedimentos_e_ferramentas":"A implementa\xe7\xe3o deste controle requer a formaliza\xe7\xe3o de atos normativos internos que\\ninstituam claramente os pap\xe9is relacionados \xe0 estrutura para governan\xe7a em privacidade e\\nseguran\xe7a da informa\xe7\xe3o. Para garantir clareza de responsabilidades e evitar sobreposi\xe7\xf5es,\\nrecomenda-se a utiliza\xe7\xe3o de matrizes de responsabilidade, como o modelo RACI –\\nRespons\xe1vel, Aprovador, Consultado e Informado –, que definem os n\xedveis de atua\xe7\xe3o de cada\\nagente envolvido. Al\xe9m disso, \xe9 necess\xe1rio estabelecer canais de comunica\xe7\xe3o estruturados\\nentre os pap\xe9is definidos, de forma a assegurar o fluxo cont\xednuo de informa\xe7\xf5es e a integra\xe7\xe3o\\nentre diferentes inst\xe2ncias da organiza\xe7\xe3o. Por fim, a efetividade da estrutura b\xe1sica de\\ngovernan\xe7a depende da implanta\xe7\xe3o de mecanismos de reporte peri\xf3dico \xe0 alta administra\xe7\xe3o,\\npermitindo acompanhamento, supervis\xe3o e tomada de decis\xe3o tempestiva.","fique_atento":null,"aplicabilidade_privacidade":""},{"id":2,"nome":"Instrumentos fundamentais","texto":"O controle de instrumentos fundamentais re\xfane os programas, pol\xedticas e mecanismos\\nindispens\xe1veis para a operacionaliza\xe7\xe3o da governan\xe7a em privacidade e seguran\xe7a da\\ninforma\xe7\xe3o. Ele traduz em instrumentos pr\xe1ticos e normativos os pap\xe9is definidos no controle\\nde estrutura\xe7\xe3o b\xe1sica para governan\xe7a.","por_que_implementar":"Mesmo com pap\xe9is bem definidos, a governan\xe7a n\xe3o se concretiza sem instrumentos formais\\nque deem sustenta\xe7\xe3o \xe0s pr\xe1ticas institucionais. Este controle garante coer\xeancia, padroniza\xe7\xe3o\\ne conformidade dos processos, permitindo que o PPSI seja aplicado de forma uniforme em\\ntoda a organiza\xe7\xe3o.","procedimentos_e_ferramentas":"A ado\xe7\xe3o deste controle pressup\xf5e a elabora\xe7\xe3o, aprova\xe7\xe3o e publica\xe7\xe3o formal dos\\ninstrumentos de privacidade e seguran\xe7a da informa\xe7\xe3o, assegurando que sejam submetidos a\\nrevis\xf5es peri\xf3dicas para manuten\xe7\xe3o de sua atualidade e ader\xeancia legal. Esses documentos\\ndevem ser disponibilizados de maneira acess\xedvel a todos os agentes p\xfablicos ou partes\\ninteressadas, de modo a garantir conhecimento institucional e aplica\xe7\xe3o uniforme. \xc9 igualmente\\nrelevante promover a integra\xe7\xe3o entre os programas de privacidade e de seguran\xe7a da\\ninforma\xe7\xe3o, de forma que atuem de maneira coordenada e complementar. Al\xe9m disso, a\\nado\xe7\xe3o de processos estruturados de gest\xe3o de risco e de conformidade fortalece a base de\\ngovernan\xe7a, enquanto o monitoramento cont\xednuo da aplica\xe7\xe3o dos instrumentos garante sua\\nefetividade. Por fim, recomenda-se que os processos institucionais de privacidade e seguran\xe7a\\nda informa\xe7\xe3o sejam incorporados \xe0s avalia\xe7\xf5es internas, de modo a verificar a conformidade\\ne melhorar a efic\xe1cia dos processos.","fique_atento":null,"aplicabilidade_privacidade":""},{"id":3,"nome":"Invent\xe1rio de ativos institucionais","texto":"Gerenciar ativamente (inventariar, rastrear e corrigir) todos os ativos institucionais (dispositivos\\nde usu\xe1rio final, incluindo port\xe1teis e m\xf3veis; dispositivos de rede; dispositivos n\xe3o\\ncomputacionais/IoT e servidores) conectados \xe0 infraestrutura fisicamente, virtualmente ou\\nremotamente e aqueles dentro de ambientes de nuvem, para conhecer com precis\xe3o a\\ntotalidade dos ativos que precisam ser monitorados e protegidos na organiza\xe7\xe3o. Isso tamb\xe9m\\najudar\xe1 a identificar ativos n\xe3o autorizados e n\xe3o gerenciados objetivando remo\xe7\xe3o ou\\nremedia\xe7\xe3o.","por_que_implementar":"A organiza\xe7\xe3o n\xe3o pode defender o que n\xe3o sabe que possui. O controle gerenciado de todos\\nos ativos institucionais tamb\xe9m desempenha um papel cr\xedtico no monitoramento de seguran\xe7a,\\nresposta a incidentes, backup e recupera\xe7\xe3o de sistemas. As organiza\xe7\xf5es devem saber quais\\ndados s\xe3o cr\xedticos para elas, e o gerenciamento adequado de ativos institucionais ajudar\xe1 a\\nidentificar quais cont\xeam ou gerenciam esses dados cr\xedticos, para que os controles de\\nseguran\xe7a apropriados possam ser aplicados.\\nAtivos adicionais que se conectam \xe0 rede da organiza\xe7\xe3o (por exemplo, sistemas de\\ndemonstra\xe7\xe3o, sistemas de teste tempor\xe1rios, redes de convidados) devem ser identificados\\ne/ou isolados para evitar que o acesso advers\xe1rio afete a seguran\xe7a das opera\xe7\xf5es da\\norganiza\xe7\xe3o.\\nAl\xe9m disso, dispositivos port\xe1teis de usu\xe1rios finais se conectam periodicamente \xe0 rede e\\ndepois desaparecem, tornando o invent\xe1rio de ativos desafiador neste cen\xe1rio din\xe2mico. Da\\nmesma forma, ambientes de nuvem e m\xe1quinas virtuais podem ser dif\xedceis de rastrear em\\ninvent\xe1rios de ativos quando est\xe3o desligados ou pausados. Manter uma vis\xe3o atualizada e\\nprecisa dos ativos \xe9 um processo cont\xednuo e din\xe2mico.","procedimentos_e_ferramentas":"Este controle requer a\xe7\xf5es t\xe9cnicas e procedimentais, unidas em uma estrat\xe9gia para\\npromover o gerenciamento do invent\xe1rio de ativos institucionais. Para auxiliar na\\nimplementa\xe7\xe3o deste controle, as organiza\xe7\xf5es podem aproveitar ferramentas de seguran\xe7a j\xe1\\ninstaladas em ativos institucionais ou usadas na rede, incluindo tecnologias para varredura de\\ndescoberta da rede com um scanner de vulnerabilidades, revisar logs antimalware, logs de\\nportais de seguran\xe7a de endpoint, logs de rede de switches ou logs de autentica\xe7\xe3o e\\ngerenciar os resultados em uma planilha ou banco de dados. Mesmo para pequenas\\norganiza\xe7\xf5es, raramente h\xe1 uma \xfanica fonte para realizar o invent\xe1rio de ativos institucionais,\\npois nem sempre os ativos s\xe3o provisionados pelo departamento de TI. A realidade \xe9 que\\ndiversas fontes precisam ser consideradas para se ter um invent\xe1rio de alta confiabilidade.\\nOrganiza\xe7\xf5es mais complexas podem adotar produtos mais abrangentes e de larga escala.\\nAl\xe9m das fontes de ativos mencionadas acima para pequenas organiza\xe7\xf5es, as maiores\\npodem coletar dados de portais e logs em nuvem de plataformas organizacionais, como: Active\\nDirectory (AD), Single Sign-On (SSO), Autentica\xe7\xe3o Multifator (MFA), Rede Privada Virtual\\n(VPN), Sistemas de Detec\xe7\xe3o de Intrus\xe3o (IDS) ou Inspe\xe7\xe3o Profunda de Pacotes (DPI),\\nGerenciamento de Dispositivos M\xf3veis (MDM) e ferramentas de varredura de vulnerabilidades.\\nExistem ferramentas e m\xe9todos que normalizam esses dados para identificar dispositivos que\\ns\xe3o \xfanicos entre essas fontes.\\nAs refer\xeancias a seguir apresentam informa\xe7\xf5es detalhadas que fundamentam e auxiliam o\\nprocesso de implementa\xe7\xe3o deste controle conforme o ambiente computacional:\\n• Guia Complementar de Seguran\xe7a da Informa\xe7\xe3o para Computa\xe7\xe3o em Nuvem:\\nhttps://www.gov.br/governodigital/pt-br/privacidade-e-seguranca/ppsi-2.0/\\n• Guias complementares do CIS Controls para dispositivos m\xf3veis, para internet das\\ncoisas e para sistemas de controle industrial, dispon\xedveis em:\\nhttps://www.cisecurity.org/controls/resources?crc=environment-specific-guidance","fique_atento":null,"aplicabilidade_privacidade":""},{"id":4,"nome":"Invent\xe1rio de solu\xe7\xf5es de software","texto":"Gerenciar ativamente (inventariar, rastrear e corrigir) todas as solu\xe7\xf5es de software na rede\\npara que somente as autorizadas sejam instaladas e possam ser executadas, e que as n\xe3o \\nautorizadas ou n\xe3o gerenciadas sejam encontradas e impedidas de serem instaladas ou\\nexecutadas.","por_que_implementar":"Um invent\xe1rio completo de solu\xe7\xf5es de software \xe9 fundamental para prevenir ataques, pois\\npermite identificar vers\xf5es vulner\xe1veis que invasores podem explorar remotamente, como por\\nmeio de navegadores desatualizados. Os invasores tamb\xe9m podem usar esse acesso para se\\nmovimentar lateralmente pela rede. Sem esse invent\xe1rio, a organiza\xe7\xe3o n\xe3o sabe quais\\nsoftwares s\xe3o vulner\xe1veis ou se h\xe1 viola\xe7\xf5es de licenciamento. Mesmo sem corre\xe7\xf5es\\ndispon\xedveis, a lista permite adotar medidas tempor\xe1rias de prote\xe7\xe3o contra ataques conhecidos\\ne “explora\xe7\xf5es de dia zero”. Al\xe9m disso, o invent\xe1rio ajuda a eliminar softwares desnecess\xe1rios\\nque representam riscos \xe0 seguran\xe7a. Assim, \xe9 essencial gerenciar todas as solu\xe7\xf5es de\\nsoftware na infraestrutura da organiza\xe7\xe3o para reduzir vulnerabilidades e proteger o ambiente.","procedimentos_e_ferramentas":"Listas de solu\xe7\xf5es de software permitidas podem ser implementadas por meio de ferramentas\\ncomerciais, pol\xedticas e recursos nativos em sistemas operacionais e su\xedtes de seguran\xe7a de\\nendpoints. Ferramentas de invent\xe1rio verificam solu\xe7\xf5es de software comuns e seus patches,\\nusando padr\xf5es como Common Platform Enumeration (CPE). Solu\xe7\xf5es modernas combinam\\nantimalware, firewall, IDS/IPS e controle por listas de permiss\xf5es, que analisam nome,\\nlocaliza\xe7\xe3o e hash de execut\xe1veis para permitir ou bloquear sua execu\xe7\xe3o. Ferramentas\\navan\xe7adas permitem personalizar listas e definir regras espec\xedficas para usu\xe1rios e hor\xe1rios,\\noferecendo controle detalhado sobre a solu\xe7\xe3o de software em uso.\\nAs refer\xeancias abaixo cont\xeam informa\xe7\xf5es detalhadas para apoio \xe0 implementa\xe7\xe3o deste\\ncontrole:\\n• Guia Complementar de Seguran\xe7a da Informa\xe7\xe3o para Computa\xe7\xe3o em Nuvem:\\nhttps://www.gov.br/governodigital/pt-br/privacidade-e-seguranca/ppsi-2.0/\\n• Guias complementares do CIS Controls para dispositivos m\xf3veis, para internet das\\ncoisas e para sistemas de controle industrial, dispon\xedveis em:\\nhttps://www.cisecurity.org/controls/resources?crc=environment-specific-guidance","fique_atento":null,"aplicabilidade_privacidade":""},{"id":5,"nome":"Prote\xe7\xe3o de dados","texto":"Aplicar processos e controles t\xe9cnicos para identificar, categorizar, utilizar, reter e descartar\\ndados com seguran\xe7a, garantindo a prote\xe7\xe3o dos dados ao longo de todo o seu ciclo de vida.","por_que_implementar":"Os dados ultrapassam os limites da organiza\xe7\xe3o, estando na nuvem, nas casas dos agentes\\np\xfablicos, em dispositivos port\xe1teis e compartilhados com parceiros, o que demanda gest\xe3o e\\nprote\xe7\xf5es adequadas ao longo de todo o ciclo de vida dos dados, incluindo aspectos de\\nconformidade.\\nAl\xe9m dos dados cr\xedticos para as estrat\xe9gias dos diferentes \xf3rg\xe3os, existem dados relacionados\\na finan\xe7as, propriedade intelectual e dados de cidad\xe3os custodiados pela organiza\xe7\xe3o.\\nInvasores buscam extrair esses dados confidenciais, mas muitas organiza\xe7\xf5es n\xe3o monitoram\\no tr\xe1fego de sa\xedda, ficando vulner\xe1veis. Al\xe9m de ataques na rede, h\xe1 riscos como roubo f\xedsico\\nde dispositivos e amea\xe7as \xe0 parceiros que armazenam esses dados. A perda de controle sobre\\nesses dados gera impactos graves, muitas vezes decorrentes de m\xe1 gest\xe3o e erros humanos.","procedimentos_e_ferramentas":"\xc9 fundamental que a organiza\xe7\xe3o estabele\xe7a um processo de gerenciamento de dados com\\ndiretrizes para categoriza\xe7\xe3o, prote\xe7\xe3o, manuseio, reten\xe7\xe3o e descarte. Tamb\xe9m deve haver\\num processo para tratar poss\xedveis viola\xe7\xf5es de dados que se integre ao plano de resposta a\\nincidentes e aos planos de conformidade e comunica\xe7\xe3o. Os dados devem ser categorizados\\nconsiderando os diferentes n\xedveis de criticidade. Em seguida, criar um invent\xe1rio que mapeie os\\ndados, os softwares que os acessam e os ativos que os hospedam. A rede deve ser\\nsegmentada conforme n\xedveis de criticidade, considerando a utiliza\xe7\xe3o de firewalls ou outros\\nrecursos tecnol\xf3gicos para controlar o acesso a cada segmento e aplicando regras de acesso\\nde usu\xe1rios para permitir o acesso aos dados apenas \xe0queles que realmente necessitam.\\nPara uma abordagem mais abrangente deste t\xf3pico, os seguintes recursos podem ser\\nconsultados para auxiliar na prote\xe7\xe3o de dados:\\n• NIST\xae SP 800-88r2 Diretrizes para sanitiza\xe7\xe3o de m\xeddias:\\nhttps://csrc.nist.gov/pubs/sp/800/88/r2/final\\n• NIST\xae FIPS 140-3 Requisitos de Seguran\xe7a para M\xf3dulos Criptogr\xe1ficos:\\nhttps://csrc.nist.gov/pubs/fips/140-3/final\\n• Guia Complementar de Seguran\xe7a da Informa\xe7\xe3o para Computa\xe7\xe3o em Nuvem:\\nhttps://www.gov.br/governodigital/pt-br/privacidade-e-seguranca/ppsi-2.0/\\n• Guia Complementar do CIS Controls para Dispositivos M\xf3veis:\\nhttps://www.cisecurity.org/controls/resources?crc=environment-specific-guidance","fique_atento":null,"aplicabilidade_privacidade":""},{"id":6,"nome":"Configura\xe7\xe3o segura de ativos institucionais e solu\xe7\xf5es de software","texto":"Estabelecer e manter a configura\xe7\xe3o segura de dispositivos de usu\xe1rio final, incluindo port\xe1teis\\ne m\xf3veis, dispositivos de rede, dispositivos n\xe3o computacionais/IoT e servidores, al\xe9m de\\nsolu\xe7\xf5es de software.","por_que_implementar":"Configura\xe7\xf5es padr\xe3o de ativos institucionais s\xe3o focadas em facilidade de uso, n\xe3o\\nseguran\xe7a, deixando vulnerabilidades como portas abertas, contas padr\xe3o, e solu\xe7\xf5es de\\nsoftware desnecess\xe1rios instalados que podem ser explorados por atacantes. Configura\xe7\xf5es\\nseguras devem ser mantidas e gerenciadas durante todo o ciclo de vida dos ativos para evitar\\ndegrada\xe7\xe3o da seguran\xe7a devido a atualiza\xe7\xf5es, mudan\xe7as ou instala\xe7\xf5es de novas solu\xe7\xf5es\\nde software. Isso se aplica a todos os ativos institucionais e ambientes computacionais,\\nincluindo dispositivos locais, remotos, de rede e computa\xe7\xe3o em nuvem.","procedimentos_e_ferramentas":"Recomenda-se a utiliza\xe7\xe3o de benchmarks p\xfablicos, guias, e checklists de seguran\xe7a como\\nCIS Benchmarks e NIST para estabelecer configura\xe7\xf5es seguras de ativos institucionais.\\nConfigura\xe7\xf5es padr\xe3o podem ser automatizadas com scripts de seguran\xe7a e ferramentas para\\nmedir a conformidade. Ferramentas comerciais podem aplicar configura\xe7\xf5es seguras\\nautomaticamente por agentes de software ou remotamente.\\nAlguns recursos para apoiar a implementa\xe7\xe3o deste controle incluem:\\n• Ferramenta de Avalia\xe7\xe3o de Configura\xe7\xe3o do CIS (CIS Configuration Assessment Tool,\\nCIS-CAT\xae): https://learn.cisecurity.org/cis-cat-lite\\n• CIS Benchmarks\xae Program: http://www.cisecurity.org/cis-benchmarks/\\n• NIST\xae National Checklist Program (NCP): https://nvd.nist.gov/ncp/repository","fique_atento":null,"aplicabilidade_privacidade":""},{"id":7,"nome":"Gest\xe3o de contas","texto":"Aplicar processos e ferramentas para atribuir e gerenciar autoriza\xe7\xe3o para credenciais de\\ncontas de usu\xe1rio e contas de servi\xe7os.","por_que_implementar":"Acesso n\xe3o autorizado por credenciais v\xe1lidas \xe9 uma das formas mais f\xe1ceis de invas\xe3o.\\nExistem muitas maneiras de obter acesso \xe0s contas de usu\xe1rios secretamente, incluindo:\\nsenhas fracas, contas ainda v\xe1lidas ap\xf3s um agente p\xfablico sair do \xf3rg\xe3o, contas de teste\\ninativas ou persistentes, contas compartilhadas que n\xe3o foram alteradas em meses ou anos,\\ncontas de servi\xe7o incorporadas em aplicativos para scripts, um usu\xe1rio com a mesma senha\\nque a usa para uma conta online que foi comprometida (em um dump p\xfablico de senhas),\\nengenharia social para que um usu\xe1rio forne\xe7a sua senha ou uso de malware para capturar\\nsenhas ou tokens na mem\xf3ria ou na rede.\\nContas administrativas s\xe3o alvos priorit\xe1rios por permitirem a adi\xe7\xe3o de outras contas, al\xe9m de\\naltera\xe7\xe3o nos ativos para torn\xe1-los mais vulner\xe1veis, al\xe9m de possu\xedrem outros privil\xe9gios que\\npodem impactar mais ainda o \xf3rg\xe3o. Contas de servi\xe7o tamb\xe9m s\xe3o importantes, pois\\ngeralmente s\xe3o compartilhadas entre equipes, internas e externas ao \xf3rg\xe3o, e \xe0s vezes n\xe3o\\ns\xe3o conhecidas, muitas vezes s\xe3o reveladas em auditorias.\\nSendo assim, o monitoramento e auditoria de contas s\xe3o essenciais para reduzir riscos\\ncausados por comportamento interno ou externo.","procedimentos_e_ferramentas":"Contas devem ser inventariadas, auditadas periodicamente e controladas, especialmente para\\ncontas administrativas ou de alto privil\xe9gio e contas de servi\xe7o. Contas inativas devem ser\\ndesabilitadas e, caso apropriado, removida do ativo. Recomenda-se que usu\xe1rios com acesso\\nde administrador ou outro privil\xe9gio tenham contas separadas para essas tarefas de autoridade\\nsuperior.\\nA ado\xe7\xe3o de Single Sign-On (SSO) \xe9 recomendada quando uma organiza\xe7\xe3o possui muitas\\nsolu\xe7\xf5es de software, ajudando a reduzir o n\xfamero de senhas que um usu\xe1rio precisa\\ngerenciar. Sugere-se tamb\xe9m que os ativos sejam configurados para desconectar os usu\xe1rios\\nautomaticamente ap\xf3s um per\xedodo de inatividade.\\nRecomenda-se que os usu\xe1rios utilizem gerenciadores de senhas para armazenar suas senhas\\ncom seguran\xe7a e sejam orientados para bloquear a tela ao se ausentar do dispositivo.\\nAlguns recursos relevantes para apoio na implementa\xe7\xe3o deste controle s\xe3o:\\n• Diretrizes de Identidade Digital do NIST\xae: https://pages.nist.gov/800-63-3/\\n• Guia de Pol\xedtica de Senhas do CIS: https://www.cisecurity.org/white-papers/cispassword-policy-guide","fique_atento":null,"aplicabilidade_privacidade":""},{"id":8,"nome":"Gest\xe3o de acesso","texto":"Aplicar processos e ferramentas para criar, atribuir, gerenciar e revogar credenciais de acesso\\ne privil\xe9gios para contas de usu\xe1rio, administrador e servi\xe7o para ativos de informa\xe7\xe3o.","por_que_implementar":"Enquanto o controle 5 trata especificamente do gerenciamento de contas, este controle\\nconcentra-se em gerenciar o acesso dessas contas, garantindo que os usu\xe1rios tenham acesso\\napenas aos ativos de informa\xe7\xe3o necess\xe1rios para sua fun\xe7\xe3o, garantindo que haja\\nautentica\xe7\xe3o forte para acesso \xe0 dados ou fun\xe7\xf5es organizacionais cr\xedticas.\\nControlar o acesso aos ativos \xe9 crucial para limitar o impacto de comprometimentos dos ativos.\\nPrivil\xe9gios mal distribu\xeddos facilitam ataques internos e externos, especialmente para contas\\nadministrativas. MFA e ferramentas de gerenciamento de acesso privilegiado fortalecem a\\nseguran\xe7a.","procedimentos_e_ferramentas":"Processos documentados devem ser usados para concess\xe3o e revoga\xe7\xe3o de privil\xe9gios,\\npreferencialmente automatizados. Idealmente, o controle de acesso baseado em fun\xe7\xf5es deve\\nser adotado e revisado regularmente. MFA \xe9 vital para acessos externos e privilegiados.\\nFerramentas para centralizar e gerenciar autentica\xe7\xe3o, autoriza\xe7\xe3o e MFA s\xe3o essenciais.\\nO desprovisionamento abrangente de contas \xe9 importante e deve incluir todas as contas de\\nusu\xe1rio, desde servidores at\xe9 terceirizados. As organiza\xe7\xf5es tamb\xe9m devem inventariar e\\nrastrear contas de servi\xe7o, pois um erro comum \xe9 deixar tokens ou senhas em texto n\xe3o\\ncriptografado no c\xf3digo e public\xe1-los em reposit\xf3rios de c\xf3digo baseados em nuvem p\xfablica.\\nA equipe de seguran\xe7a deve monitorar e identificar periodicamente processos em execu\xe7\xe3o\\npara determinar se algum navegador, leitor de e-mail e demais solu\xe7\xf5es de software est\xe3o\\nsendo executados com privil\xe9gios altos.\\n• Um recurso relevante \xe9 a publica\xe7\xe3o Diretrizes de Identidade Digital do NIST\xae:\\nhttps://pages.nist.gov/800-63-3/","fique_atento":null,"aplicabilidade_privacidade":""},{"id":9,"nome":"Gest\xe3o cont\xednua de vulnerabilidades","texto":"Desenvolver um plano para avaliar e monitorar continuamente vulnerabilidades em todos os\\nativos de informa\xe7\xe3o da organiza\xe7\xe3o, a fim de remediar e minimizar a janela de oportunidade\\npara atacantes. Monitorar fontes p\xfablicas e privadas em busca de novas informa\xe7\xf5es sobre\\namea\xe7as e vulnerabilidades.","por_que_implementar":"Vulnerabilidades s\xe3o alvo constante de atacantes. As equipes de seguran\xe7a devem\\nacompanhar de forma \xe1gil informa\xe7\xf5es sobre: atualiza\xe7\xf5es de solu\xe7\xf5es software, patches,\\nalertas de seguran\xe7a, boletins de amea\xe7as, entre outros, e devem revisar regularmente seu\\nambiente para identificar vulnerabilidades antes que os invasores o fa\xe7am. Vulnerabilidades\\nnovas ou desconhecidas (“zero-day”) aumentam o risco e as equipes precisam estar ciente\\ndesta possibilidade pois podem precisar implementar outros controles para mitigar o risco.\\nAs organiza\xe7\xf5es que n\xe3o avaliam sua infraestrutura em busca de vulnerabilidades e n\xe3o\\nabordam proativamente as falhas descobertas enfrentam uma probabilidade significativa de ter\\nseus ativos de informa\xe7\xe3o comprometidos. Sem gest\xe3o cont\xednua, o ambiente fica vulner\xe1vel a\\nexplora\xe7\xf5es.","procedimentos_e_ferramentas":"Planos documentados para gest\xe3o de vulnerabilidades s\xe3o necess\xe1rios. Ferramentas de\\nvarredura automatizada, tanto autenticada quanto n\xe3o autenticada, devem ser usadas\\nregularmente para identificar vulnerabilidades internas e externas. Para ajudar a padronizar as\\ndefini\xe7\xf5es de vulnerabilidades descobertas em uma organiza\xe7\xe3o, \xe9 prefer\xedvel usar ferramentas\\nde varredura de vulnerabilidades que mapeiem vulnerabilidades para um ou mais dos\\nseguintes esquemas e linguagens de classifica\xe7\xe3o de vulnerabilidades, configura\xe7\xf5es e\\nplataformas especificadas na publica\xe7\xe3o NIST SP 800-126r32\\n: Common Vulnerabilities and\\nExposures (CVE\xae), Common Configuration Enumeration (CCE), Open Vulnerability and\\nAssessment Language (OVAL\xae), Common Platform Enumeration (CPE), Common Vulnerability\\nScoring System (CVSS) ou Extensible Configuration Checklist Description Format (XCCDF). A\\nremedia\xe7\xe3o deve ser priorizada e executada conforme os riscos.\\nAl\xe9m das varreduras, outras ferramentas analisam configura\xe7\xf5es de seguran\xe7a e identificam\\nmudan\xe7as n\xe3o autorizadas ou vulnerabilidades introduzidas inadvertidamente. Organiza\xe7\xf5es\\neficientes conectam scanners a sistemas de emiss\xe3o de tickets para acompanhar a corre\xe7\xe3o\\nde vulnerabilidades e reportar \xe0 alta ger\xeancia, permitindo prioriza\xe7\xe3o e cumprimento de\\nrequisitos de conformidade.\\n2 Dispon\xedvel em https://nvlpubs.nist.gov/nistpubs/SpecialPublications/NIST.SP.800-126r3.pdf\\nDeve haver um processo de garantia de qualidade para verificar se as atualiza\xe7\xf5es de\\nconfigura\xe7\xe3o ou se os patches foram implementados corretamente em todos os ativos\\ninstitucionais relevantes.\\nPor fim, recomenda-se o seguinte recurso dedicado a este tema:\\n• servi\xe7o de an\xe1lise de vulnerabilidades do Centro Integrado de Seguran\xe7a Cibern\xe9tica\\n(CISC GOV.BR): https://www.gov.br/cisc/pt-br","fique_atento":null,"aplicabilidade_privacidade":""},{"id":10,"nome":"Gest\xe3o de registros de auditoria","texto":"Coletar, alertar, analisar e reter registros de auditoria de eventos que possam ajudar a detectar,\\ncompreender ou se recuperar de um ataque.","por_que_implementar":"Coletar e analisar logs s\xe3o atividades essenciais para detectar atividades maliciosas. Muitos\\nataques s\xf3 s\xe3o descobertos por an\xe1lise de logs, algumas vezes sendo a \xfanica evid\xeancia de um\\nataque bem-sucedido. Os registros de log tamb\xe9m s\xe3o cruciais para a resposta a incidentes.\\nAp\xf3s a detec\xe7\xe3o de um ataque, a an\xe1lise de logs pode ajudar as organiza\xe7\xf5es a\\ncompreenderem a extens\xe3o do ataque - quando e como o ataque ocorreu, quais informa\xe7\xf5es\\nforam acessadas e se os dados foram exfiltrados.\\nNo entanto, muitas organiza\xe7\xf5es n\xe3o monitoram ou analisam esses registros adequadamente,\\npermitindo invasores agirem por muito tempo sem serem detectados. Logs tamb\xe9m s\xe3o\\nfundamentais para investiga\xe7\xf5es e conformidade regulat\xf3ria.","procedimentos_e_ferramentas":"A maioria dos ativos institucionais e solu\xe7\xf5es de software oferecem recurso para registro de\\nlogs, o qual recomenda-se que seja ativado e configurado para envio para servidores de logs\\ncentralizados. Firewalls, proxies e sistemas de acesso remoto devem ser configurados para\\nregistro detalhado, quando necess\xe1rio. A reten\xe7\xe3o dos logs tamb\xe9m \xe9 importante caso seja\\nnecess\xe1ria uma investiga\xe7\xe3o de incidente, e o prazo deve estar de acordo com a legisla\xe7\xe3o\\nvigente aplic\xe1vel.\\nAl\xe9m disso, todos os ativos institucionais e solu\xe7\xf5es de software devem ser configurados para\\ncriar registros de controle de acesso quando um usu\xe1rio tenta acessar recursos sem os \\nprivil\xe9gios apropriados. Para avaliar se esse registro est\xe1 em vigor, uma organiza\xe7\xe3o deve\\nverificar periodicamente seus registros e compar\xe1-los com o invent\xe1rio de ativos institucionais e\\nsolu\xe7\xf5es de software reunidos como parte dos controles 1 e 2, a fim de garantir que cada item\\ndos invent\xe1rios esteja gerando registros periodicamente.","fique_atento":null,"aplicabilidade_privacidade":""},{"id":11,"nome":"Prote\xe7\xe3o de e-mail e navegador web","texto":"Aprimorar as prote\xe7\xf5es e detec\xe7\xf5es de amea\xe7as provenientes de e-mails e da web, pois essas\\ns\xe3o oportunidades para invasores manipularem o comportamento humano por meio de\\ndiferentes t\xe9cnicas.","por_que_implementar":"E-mail e navegadores web s\xe3o vetores comuns para diferentes tipos de ataques, incluindo\\nengenharia social e malware, pois est\xe3o diretamente expostos aos usu\xe1rios. Malwares\\nexploram vulnerabilidades de navegadores e suas extens\xf5es. Por sua vez, os e-mails s\xe3o os\\nprincipais canais para phishing, impactando a seguran\xe7a das organiza\xe7\xf5es.","procedimentos_e_ferramentas":"Manter apenas vers\xf5es suportadas pelos seus fabricantes de navegadores (incluindo suas\\nextens\xf5es) e clientes de e-mail. Restringir extens\xf5es n\xe3o autorizadas e de fontes n\xe3o\\nconfi\xe1veis. Usar filtros DNS nativos dos navegadores para bloquear sites maliciosos, al\xe9m de\\nfiltros de URL na rede. Considerar tamb\xe9m a assinatura de servi\xe7os de filtragem de DNS para\\nbloquear tentativas de acesso.\\nImplementar filtragem de spam e verifica\xe7\xe3o de malware no gateway de e-mail, bem como\\nDomain-Based Message Authentication, Reporting, and Conformance (DMARC), ajuda a\\nreduzir atividades de spam e phishing. Al\xe9m de filtros com base no remetente, recomenda-se\\nbloquear tipos de arquivos n\xe3o necess\xe1rios no gateway de e-mail. A instala\xe7\xe3o de uma\\nferramenta de criptografia para proteger e-mails e comunica\xe7\xf5es adiciona outra camada de\\nseguran\xe7a para o usu\xe1rio e para a rede. Prote\xe7\xf5es de antiv\xedrus e sandboxing para servidores\\nde e-mail tamb\xe9m s\xe3o fatores que auxiliam na mitiga\xe7\xe3o do risco.\\nComo os ataques de phishing por e-mail evoluem constantemente para burlar os filtros de\\nspam, antiv\xedrus, sandboxing e demais medidas t\xe9cnicas de seguran\xe7a da informa\xe7\xe3o, \xe9\\nfundamental conscientizar os agentes p\xfablicos para que saibam identificar mensagens\\nsuspeitas e as reportem \xe0 Equipe de Preven\xe7\xe3o, Tratamento e Resposta a Incidentes\\nCibern\xe9ticos (ETIR). Realizar simula\xe7\xf5es regulares de phishing \xe9 uma pr\xe1tica eficaz para \\nconscientizar os agentes p\xfablicos, ajudando-os a reconhecer diferentes tipos de ataques e a\\nacompanhar a evolu\xe7\xe3o dessas amea\xe7as ao longo do tempo.","fique_atento":null,"aplicabilidade_privacidade":""},{"id":12,"nome":"Defesa contra malware","texto":"Prevenir a instala\xe7\xe3o, dissemina\xe7\xe3o e execu\xe7\xe3o de aplicativos, c\xf3digos ou scripts maliciosos\\nem ativos institucionais.","por_que_implementar":"Software maliciosos s\xe3o uma amea\xe7a constante, com finalidades diversas como captura de\\ncredenciais, roubo e destrui\xe7\xe3o de dados. O malware evolui usando t\xe9cnicas como\\naprendizado de m\xe1quina para evitar ou desabilitar defesas. Ele entra nas organiza\xe7\xf5es por\\nvulnerabilidades em dispositivos de usu\xe1rios finais, anexos de e-mail, p\xe1ginas web, servi\xe7os\\nem nuvem, dispositivos m\xf3veis e m\xeddias remov\xedveis, explorando comportamentos inseguros\\ncomo clicar em links, abrir anexos ou usar pen drives USB.\\nAs defesas contra malware devem operar de forma automatizada, atualizada rapidamente e\\nintegradas a processos como gerenciamento de vulnerabilidades e gest\xe3o de incidentes, sendo\\nimplantadas em todos os pontos de entrada e ativos institucionais para detectar, impedir a\\ndissemina\xe7\xe3o e controlar a execu\xe7\xe3o do c\xf3digo malicioso.","procedimentos_e_ferramentas":"A prote\xe7\xe3o eficaz contra malware inclui su\xedtes tradicionais de preven\xe7\xe3o e detec\xe7\xe3o em\\nendpoints, com atualiza\xe7\xf5es automatizadas dos fornecedores para manter os Indicadores de\\nComprometimento (IOCs) atualizados. Essas ferramentas devem ser gerenciadas\\ncentralizadamente para garantir consist\xeancia em toda a infraestrutura.\\nAl\xe9m de bloquear e identificar malware, este controle destaca a import\xe2ncia da coleta\\ncentralizada de logs para suportar alertas, identifica\xe7\xe3o e resposta a incidentes. Invasores\\nutilizam t\xe9cnicas Living Off The Land (LotL), empregando recursos j\xe1 existentes no ambiente\\npara evitar detec\xe7\xe3o. Habilitar o registro em log facilita o acompanhamento e a compreens\xe3o\\ndos eventos de seguran\xe7a – o controle 13 apresenta medidas detalhadas nesta perspectiva.\\n• Para entender como os controles do PPSI aplicam-se \xe0s t\xe9cnicas mais comuns de\\nLotL, consulte: https://www.cisecurity.org/controls/resources?crc=minimize-your-threats","fique_atento":null,"aplicabilidade_privacidade":""},{"id":13,"nome":"Recupera\xe7\xe3o de dados","texto":"Estabelecer e manter pr\xe1ticas de realiza\xe7\xe3o de c\xf3pias de seguran\xe7a e recupera\xe7\xe3o de dados\\nsuficientes para restaurar os ativos institucionais para um estado confi\xe1vel e pr\xe9-incidente.","por_que_implementar":"Na tr\xedade da seguran\xe7a da informa\xe7\xe3o – confidencialidade, integridade e disponibilidade (CID)\\n–, a disponibilidade dos dados \xe9, em alguns casos, t\xe3o cr\xedtica quanto a sua confidencialidade,\\npois dados indispon\xedveis ou n\xe3o confi\xe1veis impactam decis\xf5es de neg\xf3cios. Al\xe9m de poss\xedveis\\nerros humanos, invasores fazem altera\xe7\xf5es dif\xedceis de detectar em configura\xe7\xf5es, contas e\\nadicionam software e scripts maliciosos. Por isso, ter c\xf3pias de seguran\xe7a ou imagens recentes\\n\xe9 essencial para recuperar os ativos a um estado confi\xe1vel.\\nO ransomware, apesar de n\xe3o ser novidade, aumentou muito e evoluiu para extors\xe3o, onde\\ndados s\xe3o exfiltrados antes da criptografia, com exig\xeancia de pagamento para evitar a\\ndivulga\xe7\xe3o. Ter c\xf3pias de seguran\xe7a ajuda a restaurar sistemas, mas n\xe3o evita a exposi\xe7\xe3o\\ndos dados. Seguir os demais controles CIS auxiliar\xe1 na preven\xe7\xe3o dos riscos de ransomware\\npela melhoria da higiene cibern\xe9tica.","procedimentos_e_ferramentas":"Os procedimentos de realiza\xe7\xe3o de c\xf3pias de seguran\xe7a e recupera\xe7\xe3o de dados devem estar\\nrelacionados com o processo de gerenciamento de dados do controle 3, incluindo backups\\nbaseados na criticidade dos dados para a organiza\xe7\xe3o e requisitos legais de reten\xe7\xe3o dos\\ndados, determinando a frequ\xeancia e o tipo de backup (completo ou incremental).\\nTrimestralmente, ou ap\xf3s mudan\xe7as em processos ou tecnologias, recomenda-se que uma\\nequipe realize testes de restaura\xe7\xe3o de c\xf3pias de seguran\xe7a em ambiente controlado,\\nverificando a integridade e funcionalidade do sistema operacional, solu\xe7\xf5es de software e\\ndados, avaliando o tempo do processo de restaura\xe7\xe3o e seu impacto em casos de\\nnecessidade.","fique_atento":null,"aplicabilidade_privacidade":""},{"id":14,"nome":"Gest\xe3o de infraestrutura de rede","texto":"Estabelecer, implementar e gerenciar ativamente (rastrear, reportar, corrigir) os ativos de rede,\\na fim de evitar que atacantes explorem servi\xe7os de rede e pontos de acesso vulner\xe1veis.","por_que_implementar":"Uma infraestrutura de rede segura \xe9 essencial para a defesa contra ataques, incluindo\\narquitetura adequada, tratamento de vulnerabilidades introduzidas por configura\xe7\xf5es padr\xe3o,\\nmonitoramento de altera\xe7\xf5es e reavalia\xe7\xe3o das configura\xe7\xf5es. Essa infraestrutura abrange\\ngateways f\xedsicos e virtualizados, firewalls, pontos de acesso sem fio, roteadores e switches.\\nConfigura\xe7\xf5es padr\xe3o focam na facilidade de uso, n\xe3o na seguran\xe7a, podendo conter servi\xe7os\\ne portas abertas, contas e senhas padr\xe3o, protocolos vulner\xe1veis e solu\xe7\xf5es de software\\ndesnecess\xe1rias. Invasores exploram essas vulnerabilidades e inconsist\xeancias em regras de\\nfirewall, roteadores e switches para acessar redes, redirecionar tr\xe1fego e interceptar dados.\\nA seguran\xe7a de rede exige reavalia\xe7\xf5es regulares de arquitetura, configura\xe7\xf5es, controles de\\nacesso e fluxos de tr\xe1fego, pois as vulnerabilidades de seguran\xe7a podem surgir a partir de\\nexce\xe7\xf5es comerciais que n\xe3o s\xe3o removidas ou analisadas adequadamente ao longo do\\ntempo.","procedimentos_e_ferramentas":"As organiza\xe7\xf5es devem garantir documenta\xe7\xe3o completa da infraestrutura de rede e manter\\ndiagramas de arquitetura atualizados, incluindo arquitetura de seguran\xe7a. Os componentes\\ndevem ter suporte para patches e atualiza\xe7\xf5es, sendo substitu\xeddos antes do fim de vida (End of\\nLine, EOL) ou isolados por controles de mitiga\xe7\xe3o. Dessa forma, \xe9 necess\xe1rio monitorar\\nvers\xf5es e configura\xe7\xf5es para identificar vulnerabilidades e atualizar dispositivos de rede para\\nvers\xf5es seguras e est\xe1veis sem impactar a infraestrutura.\\n\xc9 necess\xe1rio ter gerenciamento completo de contas para controle de acesso, registro e\\nmonitoramento, com administra\xe7\xe3o da infraestrutura realizada por meio de protocolos seguros,\\nautentica\xe7\xe3o forte (MFA para PAM, Privileged Access Management) e a partir de dispositivos\\nou redes dedicadas.\\nFerramentas comerciais podem automatizar a avalia\xe7\xe3o de regras de filtragem de rede,\\ndetectando inconsist\xeancias ou erros em conjuntos de regras e Listas de Controle de Acesso\\n(Access Control Lists, ACLs), e devem ser usadas ap\xf3s altera\xe7\xf5es significativas nessas regras.\\n• Para obter orienta\xe7\xf5es sobre teletrabalho e pequenos escrit\xf3rios, consulte o Guia de\\nSeguran\xe7a de Rede para Teletrabalho e Pequenos Escrit\xf3rios do CIS Controls,\\nconsulte: https://www.cisecurity.org/controls/resources?crc=environment-specificguidance","fique_atento":null,"aplicabilidade_privacidade":""},{"id":15,"nome":"Monitoramento e defesa de rede","texto":"Implementar processos e ferramentas para estabelecer e manter monitoramento abrangente de\\nrede e defesa contra amea\xe7as de seguran\xe7a em toda a infraestrutura de rede e base de\\nusu\xe1rios da organiza\xe7\xe3o.","por_que_implementar":"Mesmo que as defesas de rede funcionem e auxiliem na mitiga\xe7\xe3o de riscos, elas n\xe3o s\xe3o\\nperfeitas, sendo necess\xe1rio compreender a postura de risco da organiza\xe7\xe3o para configur\xe1-las,\\najust\xe1-las e registr\xe1-las corretamente. Configura\xe7\xf5es incorretas devido a erro humano ou\\ndesconhecimento dos recursos das ferramentas podem gerar falsa sensa\xe7\xe3o de seguran\xe7a.\\nFerramentas de seguran\xe7a s\xe3o eficazes apenas com monitoramento cont\xednuo que alerte e\\npermita resposta r\xe1pida a incidentes, envolvendo visibilidade total dos vetores de ataque e o\\nuso de humanos no processo de detec\xe7\xe3o, an\xe1lise e resposta. Grandes organiza\xe7\xf5es ou\\naquelas fortemente visadas devem ter opera\xe7\xf5es de seguran\xe7a para prevenir, detectar e\\nresponder rapidamente, gerando relat\xf3rios e m\xe9tricas que aprimoram pol\xedticas e promovam a\\nconformidade regulat\xf3ria.\\nA consci\xeancia situacional – capacidade de perceber, compreender e antecipar elementos e\\nriscos no ambiente em um dado espa\xe7o-tempo, permitindo tomada de decis\xe3o r\xe1pida e eficaz –\\ntem como principal benef\xedcio aumentar a velocidade de detec\xe7\xe3o e resposta, reduzindo o\\nimpacto de malware, roubo de credenciais ou comprometimento de dados. Por meio dela,\\norganiza\xe7\xf5es catalogam T\xe1ticas, T\xe9cnicas e Procedimentos (TTPs) e IOCs, permitindo uma\\nabordagem mais proativa e recupera\xe7\xe3o mais r\xe1pida com informa\xe7\xf5es completas para\\nestrat\xe9gias eficientes.","procedimentos_e_ferramentas":"A consci\xeancia situacional n\xe3o exige necessariamente um Centro de Opera\xe7\xf5es de Seguran\xe7a\\n(Security Operations Center, SOC) e come\xe7a com o entendimento das fun\xe7\xf5es cr\xedticas,\\narquiteturas, dados, servi\xe7os de fornecedores e demais ativos institucionais da organiza\xe7\xe3o.\\nIsso \xe9 a base para cria\xe7\xe3o de uma arquitetura de seguran\xe7a, aplica\xe7\xe3o de medidas t\xe9cnicas,\\nregistro de eventos de seguran\xe7a, monitoramento e procedimentos de resposta, conduzidos\\npor uma equipe treinada, internamente ou por terceiros.\\nA tecnologia \xe9 fundamental para coletar e analisar dados, monitorando redes e demais ativos\\ninternos e externos, incluindo plataformas em nuvem. Encaminhar eventos de seguran\xe7a para\\nsolu\xe7\xf5es de Gerenciamento de Eventos e Informa\xe7\xf5es de Seguran\xe7a (Security Information and\\nEvent Management, SIEM) e ferramentas de correla\xe7\xe3o de eventos pode agregar valor, mas\\nn\xe3o \xe9 suficiente para oferecer uma vis\xe3o completa. Essas ferramentas n\xe3o substituem\\nprofissionais qualificados, essenciais para detectar e entender ataques e promover a\\nimplanta\xe7\xe3o adequada e ajustes necess\xe1rios nessas solu\xe7\xf5es.\\nCom a maturidade do processo, a organiza\xe7\xe3o desenvolver\xe1 uma base de conhecimento para\\navaliar riscos, construindo capacidade interna de intelig\xeancia contra amea\xe7as e coletando TTPs\\nde advers\xe1rios. Algumas organiza\xe7\xf5es maduras podem avan\xe7ar para ca\xe7a \xe0s amea\xe7as,\\nrevisando manualmente logs, fluxos de dados e tr\xe1fego para identificar anomalias.","fique_atento":null,"aplicabilidade_privacidade":""},{"id":16,"nome":"Conscientiza\xe7\xe3o e treinamento de compet\xeancias","texto":"Estabelecer e manter a\xe7\xf5es de treinamento e um programa de conscientiza\xe7\xe3o em seguran\xe7a\\nda informa\xe7\xe3o cont\xednuo para influenciar o comportamento dos agentes p\xfablicos, tornando-os\\nqualificados e conscientes para reduzir os riscos de seguran\xe7a da informa\xe7\xe3o para a\\norganiza\xe7\xe3o.","por_que_implementar":"As a\xe7\xf5es dos agentes p\xfablicos s\xe3o fundamentais para o sucesso do aprimoramento da\\nmaturidade em seguran\xe7a da informa\xe7\xe3o nas organiza\xe7\xf5es. \xc9 mais f\xe1cil para um invasor\\ninduzir um usu\xe1rio a clicar em um link ou abrir um anexo de e-mail do que explorar diretamente\\numa vulnerabilidade de rede.\\nUsu\xe1rios, intencionalmente ou n\xe3o, podem causar incidentes por manuseio incorreto de dados\\ncr\xedticos para a organiza\xe7\xe3o, envio errado de e-mails, perda de dispositivos, uso de senhas\\nfracas ou repetidas em sites p\xfablicos.\\nNenhum programa de seguran\xe7a \xe9 eficaz sem abordar o fator humano, considerando que\\ndiferentes n\xedveis e fun\xe7\xf5es na organiza\xe7\xe3o apresentam riscos variados, como executivos com\\ndados mais cr\xedticos e administradores com acesso privilegiado.\\nDessa forma, a implementa\xe7\xe3o de um programa de conscientiza\xe7\xe3o sobre seguran\xe7a da\\ninforma\xe7\xe3o cont\xednuo, e sua atualiza\xe7\xe3o regular, s\xe3o essenciais para fortalecer a cultura de\\nseguran\xe7a e reduzir pr\xe1ticas arriscadas.","procedimentos_e_ferramentas":"Um programa eficaz de conscientiza\xe7\xe3o em seguran\xe7a da informa\xe7\xe3o vai al\xe9m do treinamento\\nanual com v\xeddeos e testes de phishing, incluindo mensagens frequentes e atualizadas sobre\\ntemas relevantes, como uso de senhas fortes e campanhas de phishing sazonais.\\nO programa de conscientiza\xe7\xe3o deve considerar requisitos regulat\xf3rios e amea\xe7as espec\xedficas\\nda organiza\xe7\xe3o, al\xe9m de abranger diferentes fun\xe7\xf5es, como tentativas de comprometimento de\\ncaixas de e-mail (Business Email Compromise, BEC) para a equipe financeira, simulando\\npedidos fraudulentos de transfer\xeancia ou altera\xe7\xe3o de dados banc\xe1rios.\\nPara uma abordagem mais abrangente deste t\xf3pico, e a constru\xe7\xe3o de um programa eficaz de\\nconscientiza\xe7\xe3o sobre seguran\xe7a da informa\xe7\xe3o, os seguintes recursos s\xe3o \xfateis:\\n• materiais educativos disponibilizados pelo Centro de Excel\xeancia em Privacidade e\\nSeguran\xe7a (CEPS GOV.BR): https://www.gov.br/governodigital/pt-br/privacidade-eseguranca/centro-de-excelencia-em-privacidade-e-seguranca\\n• NIST\xae SP 800-50 - Construindo um Programa de Aprendizagem em Seguran\xe7a\\nCibern\xe9tica e Privacidade: https://csrc.nist.gov/pubs/sp/800/50/r1/final\\n• Centro Nacional de Seguran\xe7a Cibern\xe9tica (Reino Unido):\\nhttps://www.ncsc.gov.uk/guidance/10-steps-user-education-and-awareness\\n• EDUCAUSE: https://www.educause.edu/focus-areas-and-initiatives/policy-andsecurity/cybersecurity-program/awareness-campaigns\\n• Alian\xe7a Nacional de Seguran\xe7a Cibern\xe9tica (NCSA): https://staysafeonline.org/\\n• SANS: https://www.sans.org/security-awareness-training/resources","fique_atento":null,"aplicabilidade_privacidade":""},{"id":17,"nome":"Gest\xe3o de provedor de servi\xe7os","texto":"Desenvolver um processo para avaliar provedores de servi\xe7os que det\xeam dados cr\xedticos para a\\norganiza\xe7\xe3o ou s\xe3o respons\xe1veis por plataformas ou processos cr\xedticos de TI do \xf3rg\xe3o, a fim\\nde garantir que esses provedores estejam protegendo essas plataformas e dados\\nadequadamente.","por_que_implementar":"As organiza\xe7\xf5es dependem de fornecedores e parceiros para gerenciar dados e infraestrutura\\nessencial. Viola\xe7\xf5es em terceiros j\xe1 causaram impactos significativos, como comprometimento\\nde cart\xf5es de pagamento por invasores em provedores menores e ataques de ransomware que\\ninterrompem neg\xf3cios, podendo afetar diretamente a organiza\xe7\xe3o principal.\\nRegulamenta\xe7\xf5es exigem que a prote\xe7\xe3o de dados se estenda aos provedores de servi\xe7os,\\ncomo a Health Insurance Portability and Accountability Act (HIPAA), Federal Financial\\nInstitutions Examination Council (FFIEC) e os Fundamentos Cibern\xe9ticos do Reino Unido,\\ntornando a gest\xe3o de riscos de terceiros parte essencial da Governan\xe7a, Risco e Conformidade\\n(GRC), pois riscos n\xe3o gerenciados internamente s\xe3o transferidos a entidades externas.\\nNa Administra\xe7\xe3o P\xfablica federal direta, aut\xe1rquica e fundacional h\xe1 diversas regulamenta\xe7\xf5es\\naplic\xe1veis \xe0s contrata\xe7\xf5es. Nesse contexto, esses instrumentos foram especificados nas\\nnormas de refer\xeancia correspondentes a cada medida deste controle, devendo ser avaliados\\npara garantir a correta implementa\xe7\xe3o das a\xe7\xf5es.\\nApesar da longa pr\xe1tica de revis\xe3o das medidas de seguran\xe7a da informa\xe7\xe3o aplicadas por\\nterceiros contratados, n\xe3o h\xe1 padr\xe3o universal para avalia\xe7\xe3o, o que leva a auditorias\\nfrequentes e variadas que impactam a produtividade dos provedores.\\nOrganiza\xe7\xf5es menores geralmente representam riscos maiores que grandes fornecedores de\\nservi\xe7os cr\xedticos, especialmente porque estes podem subcontratar terceiros adicionais para\\nfornecer plugins ou servi\xe7os que suportam a oferta principal.","procedimentos_e_ferramentas":"A maioria das organiza\xe7\xf5es usa listas de verifica\xe7\xe3o padr\xe3o, como ISO 27001 ou Controles\\nCIS, muitas vezes gerenciadas por planilhas, embora plataformas online para gest\xe3o\\ncentralizada estejam dispon\xedveis. Plataformas para gest\xe3o de provedores oferecem invent\xe1rios\\ne pontua\xe7\xf5es din\xe2micas de risco baseadas em avalia\xe7\xf5es t\xe9cnicas passivas ou enriquecidas\\npor outras organiza\xe7\xf5es, auxiliando decis\xf5es mais informadas.\\nO foco deste Controle CIS \xe9 no processo em si, que deve ser revisado anualmente, pois\\nrelacionamentos e dados podem mudar. Independentemente do porte, a organiza\xe7\xe3o deve ter\\npol\xedtica de revis\xe3o de prestadores, invent\xe1rio atualizado deles e classifica\xe7\xe3o de risco conforme\\no impacto potencial nos neg\xf3cios, incluindo cl\xe1usulas contratuais de responsabiliza\xe7\xe3o por \\nincidentes. Provedores com contrato de seguran\xe7a gerenciada, garantias e seguro cibern\xe9tico\\najudam a reduzir riscos.\\nAo encerrar contratos, \xe9 fundamental realizar desativa\xe7\xe3o segura dos provedores, como\\ndesativar contas, encerrar fluxos de dados e promover o descarte seguro de dados nos\\nsistemas do provedor de servi\xe7os.","fique_atento":null,"aplicabilidade_privacidade":""},{"id":18,"nome":"Seguran\xe7a de aplica\xe7\xf5es","texto":"Gerenciar o ciclo de vida de seguran\xe7a de todas as solu\xe7\xf5es de software desenvolvidas,\\nhospedadas ou adquiridas internamente, com o objetivo de prevenir, detectar e corrigir\\nvulnerabilidades de seguran\xe7a antes que elas possam impactar a organiza\xe7\xe3o.","por_que_implementar":"Solu\xe7\xf5es de software permitem que usu\xe1rios acessem e gerenciem dados de forma alinhada\\n\xe0s fun\xe7\xf5es de neg\xf3cios, reduzindo a necessidade de interagir com fun\xe7\xf5es complexas de\\nsistemas, como acessar e manipular bancos de dados diretamente. Como estas solu\xe7\xf5es s\xe3o\\nusadas para gerenciar dados cr\xedticos e controlar acessos, podem ser exploradas por invasores\\npara comprometer informa\xe7\xf5es. Por isso, proteger as credenciais dos usu\xe1rios – conforme\\nmedidas previstas no Controle 6 –, especialmente as de solu\xe7\xf5es de software, \xe9 fundamental.\\nVulnerabilidades em solu\xe7\xf5es de software est\xe3o entre os vetores de ataques preferidos pelos\\natacantes. Solu\xe7\xf5es de software modernas s\xe3o complexas, executadas em m\xfaltiplas\\nplataformas e frequentemente desenvolvidas com ciclos DevOps curtos, usando combina\xe7\xf5es\\nde frameworks, bibliotecas e c\xf3digo existente. As vulnerabilidades surgem por concep\xe7\xe3o\\ninsegura das solu\xe7\xf5es, infraestrutura vulner\xe1vel, erros de codifica\xe7\xe3o, autentica\xe7\xe3o fraca e\\ntestes insuficientes. Invasores exploram falhas como estouros de buffer, inje\xe7\xe3o de SQL,\\nCross-Site Scripting (XSS) e outras para acessar dados ou controlar ativos vulner\xe1veis,\\npodendo tamb\xe9m usar tecnologias para coletar credenciais ou instalar malware.\\nO uso crescente de Software como Servi\xe7o (SaaS), desenvolvidas e gerenciadas por terceiros\\nem qualquer lugar do mundo, traz desafios \xe0 visibilidade sobre pr\xe1ticas de desenvolvimento de\\nsoftware seguro para as organiza\xe7\xf5es, que precisam saber quais riscos est\xe3o assumindo ao\\nusar essas plataformas.","procedimentos_e_ferramentas":"Para a Vers\xe3o 8, o CIS fez parceria com o SAFECode objetivando desenvolver os\\nprocedimentos e medidas deste controle, focando nas a\xe7\xf5es mais cr\xedticas. Essas a\xe7\xf5es\\nbaseiam-se em um artigo complementar do SAFECode (referenciado nos recursos\\ncomplementares ao final desta subse\xe7\xe3o), que oferece uma abordagem aprofundada.\\nO SAFECode criou uma abordagem em tr\xeas n\xedveis para ajudar a identificar o Grupo de\\nDesenvolvimento (GD) conforme maturidade de programas, inspirada nos tr\xeas n\xedveis dos\\ngrupos de implementa\xe7\xe3o do CIS usados neste guia.\\n• Grupo de Desenvolvimento 1: a organiza\xe7\xe3o depende em grande parte de software\\npronto ou de c\xf3digo aberto e pacotes com apenas algumas adi\xe7\xf5es ocasionais de\\npequenas solu\xe7\xf5es de software ou c\xf3digos para sites. A organiza\xe7\xe3o \xe9 capaz de\\naplicar boas pr\xe1ticas operacionais e processuais b\xe1sicas e de gerenciar a seguran\xe7a\\ndas solu\xe7\xf5es de software fornecidas por terceiros seguindo as orienta\xe7\xf5es dos\\nControles CIS;\\n• Grupo de Desenvolvimento 2: a organiza\xe7\xe3o utiliza algumas solu\xe7\xf5es de software\\npersonalizadas, desenvolvidas internamente ou por contratados, integradas a\\ncomponentes de terceiros, operando tanto localmente quanto na nuvem. Conta com\\numa equipe de desenvolvimento que adota as melhores pr\xe1ticas em desenvolvimento\\nde software e dedica aten\xe7\xe3o especial \xe0 qualidade e \xe0 manuten\xe7\xe3o do c\xf3digo\\nterceirizado, seja ele de c\xf3digo aberto ou comercial, do qual depende;\\n• Grupo de Desenvolvimento 3: a organiza\xe7\xe3o investe significativamente em solu\xe7\xf5es de\\nsoftware personalizadas para suas opera\xe7\xf5es, hospedadas localmente, na nuvem, ou\\nambos, integrando diversos componentes de c\xf3digo aberto e comerciais. Fornecedores\\nde software e organiza\xe7\xf5es que entregam SaaS devem seguir, no m\xednimo, os\\nrequisitos do Grupo de Desenvolvimento 3.\\nO primeiro passo para um programa de seguran\xe7a de solu\xe7\xf5es de software \xe9 implementar um\\nprocesso de gerenciamento de vulnerabilidades integrado ao ciclo de desenvolvimento,\\nincluindo an\xe1lise de causa raiz para corrigir falhas e prioriza\xe7\xe3o por severidade das\\nremedia\xe7\xf5es.\\nDesenvolvedores devem ser treinados em seguran\xe7a de solu\xe7\xf5es de software e pr\xe1ticas de\\ncodifica\xe7\xe3o segura, incluindo avalia\xe7\xe3o de software, m\xf3dulos e bibliotecas de terceiros, para\\ngarantir que n\xe3o introduzam falhas. Devem saber quais componentes usar com seguran\xe7a e\\nquais desenvolver internamente.\\nVulnerabilidades na infraestrutura que suporta as solu\xe7\xf5es de software tamb\xe9m geram riscos;\\nos controles propostos no framework do PPSI 2.0 e a minimiza\xe7\xe3o da superf\xedcie de ataque\\najudam a proteger redes, sistemas e contas (controles 1-7, 12 e 13).\\nO programa ideal integra seguran\xe7a desde o in\xedcio do ciclo de desenvolvimento, unificando o\\ngerenciamento de vulnerabilidades de seguran\xe7a com o processo padr\xe3o de corre\xe7\xe3o de bugs.\\nEquipes maiores devem adotar a modelagem de amea\xe7as na fase de concep\xe7\xe3o para\\nidentificar falhas graves antes da codifica\xe7\xe3o.\\nEquipes maduras podem usar programas de recompensa por bugs para complementar a\\nseguran\xe7a interna, identificando vulnerabilidades cr\xedticas.\\nEm 2020, o NIST publicou o Secure Software Development Framework (SSDF), consolidando\\nmelhores pr\xe1ticas para planejamento e avalia\xe7\xe3o da seguran\xe7a de solu\xe7\xf5es de software, que \\npode ser usado para estabelecer requisitos e avaliar processos de desenvolvimento de\\nfornecedores.\\nEstes s\xe3o alguns recursos sobre seguran\xe7a de solu\xe7\xf5es de software:\\n• SAFECode - Adendo de seguran\xe7a de solu\xe7\xf5es de software e os controles CIS:\\nhttps://safecode.org/resource-publications/cis-controls/\\n• NIST\xae SP 800-218 - Framework de Desenvolvimento de Software Seguro (Secure\\nSoftware Development Framework, SSDF): Recomenda\xe7\xf5es para Mitigar o Risco de\\nVulnerabilidades de Software: https://csrc.nist.gov/pubs/sp/800/218/final\\n• Business Software Alliance - BSA Framework para Software Seguro:\\nhttps://www.bsa.org/reports/updated-bsa-framework-for-secure-software\\n• Projeto Aberto de Seguran\xe7a em Aplica\xe7\xf5es Web (Open Worldwide Application\\nSecurity Project, OWASP)\\n: https://owasp.org/","fique_atento":null,"aplicabilidade_privacidade":""},{"id":19,"nome":"Gest\xe3o de incidentes","texto":"Estabelecer um programa para desenvolver e manter um processo de gest\xe3o de incidentes\\n(por exemplo, pol\xedticas, planos, procedimentos, fun\xe7\xf5es definidas, treinamento e\\ncomunica\xe7\xf5es) para preparar, detectar e responder rapidamente a um ataque.","por_que_implementar":"Um programa completo de seguran\xe7a da informa\xe7\xe3o deve incluir prote\xe7\xe3o, detec\xe7\xe3o, resposta\\ne recupera\xe7\xe3o, mas organiza\xe7\xf5es imaturas tendem a negligenciar as a\xe7\xf5es resposta e\\nrecupera\xe7\xe3o, limitando-se a restaurar sistemas sem compreender o incidente. O objetivo da\\nresposta a incidentes \xe9 identificar amea\xe7as, conter sua propaga\xe7\xe3o e remediar antes que\\ncausem danos, evitando um ciclo constante de ataques.\\nProte\xe7\xf5es n\xe3o s\xe3o 100% eficazes; sem um plano documentado, mesmo boas equipes ter\xe3o\\ndificuldades em conduzir investiga\xe7\xf5es, reportar, coletar dados, gerenciar responsabilidades,\\nseguir requisitos legais e comunicar-se adequadamente para entender, controlar e recuperar-se\\ndo incidente.\\nAl\xe9m da detec\xe7\xe3o, conten\xe7\xe3o e erradica\xe7\xe3o, a comunica\xe7\xe3o com as partes interessadas \xe9\\nessencial. A lideran\xe7a deve entender os impactos potenciais para priorizar decis\xf5es de\\nremedia\xe7\xe3o ou restaura\xe7\xe3o baseadas em conformidade, acordos, receita ou miss\xe3o.\\nO tempo entre o ataque e sua identifica\xe7\xe3o pode durar dias, semanas ou meses. Quanto mais\\ntempo o invasor permanecer, mais ele se integra e cria formas de manter acesso persistente.\\nEsse tempo \xe9 cr\xedtico especialmente com ransomwares, que frequentemente combinam roubo\\nde dados antes da criptografia para extors\xe3o.","procedimentos_e_ferramentas":"Mesmo em organiza\xe7\xf5es com recursos limitados para resposta a incidentes, \xe9 fundamental\\npossuir um plano documentado, incluindo fontes de prote\xe7\xe3o e detec\xe7\xe3o, contatos para suporte\\ne planos de comunica\xe7\xe3o para lideran\xe7a, agentes p\xfablicos, reguladores, parceiros e demais\\nusu\xe1rios.\\nAp\xf3s definir os procedimentos, a equipe de resposta deve realizar treinamentos peri\xf3dicos\\nbaseados em cen\xe1rios de ataque adaptados \xe0s amea\xe7as e impactos potenciais da\\norganiza\xe7\xe3o. Esses exerc\xedcios ajudam a equipe e a lideran\xe7a a entender seus pap\xe9is,\\nidentificando lacunas e atualizando processos conforme necess\xe1rio.\\nOrganiza\xe7\xf5es mais maduras devem incorporar intelig\xeancia de amea\xe7as ou ca\xe7a a amea\xe7as no\\nprocesso de resposta, permitindo uma postura proativa ao monitorar atacantes e suas t\xe1ticas,\\nmelhorando a rapidez na detec\xe7\xe3o e remedia\xe7\xe3o.\\nAs a\xe7\xf5es deste controle fornecem passos priorit\xe1rios importantes para fortalecer a seguran\xe7a\\nda informa\xe7\xe3o e devem fazer parte de qualquer plano abrangente de resposta a incidentes.\\nAl\xe9m disso, recomenda-se os seguintes recursos dedicados a este tema:\\n• servi\xe7os, alertas e recomenda\xe7\xf5es do Centro Integrado de Seguran\xe7a Cibern\xe9tica\\n(CISC GOV.BR): https://www.gov.br/cisc/pt-br\\n• Guia de Resposta a Incidentes de Seguran\xe7a Cibern\xe9tica do Council of Registered\\nSecurity Testers (CREST): o CREST fornece orienta\xe7\xe3o, padr\xf5es e conhecimento\\nsobre uma ampla variedade de t\xf3picos de defesa cibern\xe9tica - https://www.crestapproved.org/wp-content/uploads/2022/04/CSIR-Procurement-Guide-1.pdf","fique_atento":null,"aplicabilidade_privacidade":""},{"id":20,"nome":"Testes de intrus\xe3o","texto":"Testar a efic\xe1cia e a resili\xeancia dos ativos institucionais e das solu\xe7\xf5es de software,\\nidentificando e explorando vulnerabilidades e simulando os objetivos e a\xe7\xf5es de um invasor.","por_que_implementar":"Uma postura defensiva eficaz requer um programa abrangente com pol\xedticas, governan\xe7a,\\ndefesas t\xe9cnicas robustas e a\xe7\xf5es adequadas das pessoas. Em ambientes complexos e\\ndin\xe2micos, empresas devem testar periodicamente seus controles para identificar falhas e\\navaliar resili\xeancia, compreendendo testes em redes, solu\xe7\xf5es de software, dispositivos,\\nengenharia social em usu\xe1rios e controle de acesso f\xedsico.\\nTestes de penetra\xe7\xe3o s\xe3o realizados para demonstrar um ataque e respectivas\\nvulnerabilidades, verificar a opera\xe7\xe3o das defesas ou validar a implementa\xe7\xe3o correta delas.\\nTestes de penetra\xe7\xe3o independentes podem fornecer percep\xe7\xf5es valiosas sobre\\nvulnerabilidades em ativos institucionais e solu\xe7\xf5es de software, incluindo falhas em processos\\ne treinamentos, al\xe9m de avaliar a efic\xe1cia dos controles, e fazer parte de um programa\\ncont\xednuo de seguran\xe7a.\\nDiferentemente dos testes de vulnerabilidade (controle 7), que focam em identificar pontos\\nfracos conhecidos sem explorar a profundidade do ataque, os testes de penetra\xe7\xe3o envolvem\\nexplora\xe7\xe3o ativa para avaliar o impacto real. An\xe1lise de vulnerabilidade \xe9 geralmente \\nautomatizada; testes de penetra\xe7\xe3o exigem an\xe1lise humana e uso de ferramentas espec\xedficas,\\nalgumas vezes envolvendo uso de ferramentas ou scripts personalizados.","procedimentos_e_ferramentas":"O teste de penetra\xe7\xe3o inicia-se com o reconhecimento da organiza\xe7\xe3o e do ambiente, seguido\\npela varredura para identifica\xe7\xe3o de vulnerabilidades em todos os ativos em escopo, evitando\\nlistas est\xe1ticas desatualizadas. Explora\xe7\xf5es s\xe3o realizadas para demonstrar como um\\nadvers\xe1rio pode comprometer a seguran\xe7a ou alcan\xe7ar objetivos maliciosos, abrangendo\\ncontroles f\xedsicos, redes, solu\xe7\xf5es de software e engenharia social.\\nTestes de penetra\xe7\xe3o s\xe3o complexos, caros e apresentam riscos, devendo ser conduzidos por\\nprofissionais experientes. Podem causar falhas nos sistemas que v\xe3o desde poss\xedveis\\ninstabilidades, englobando seu eventual desligamento, e at\xe9 mesmo corromper dados.\\nDestaca-se que os relat\xf3rios gerados precisam ser protegidos para evitar que forne\xe7am\\ninstru\xe7\xf5es aos atacantes.\\nCada organiza\xe7\xe3o deve definir um escopo claro e regras de engajamento, focando em ativos\\ncom informa\xe7\xf5es valiosas e processos cr\xedticos, incluindo poss\xedveis solu\xe7\xf5es de software de\\nmenor valor que possam ser usados para movimentos laterais. Regras devem contemplar\\nhor\xe1rios, dura\xe7\xe3o e abordagem, com poucos informados sobre o teste e um respons\xe1vel\\ndesignado para incidentes.\\nAs medidas deste controle indicam passos priorit\xe1rios para aprimorar a seguran\xe7a. Al\xe9m disso,\\nrecomenda-se o uso de alguns dos excelentes recursos abrangentes dedicados a este tema\\npara apoiar a realiza\xe7\xe3o de testes de intrus\xe3o, al\xe9m do planejamento, a gest\xe3o e a elabora\xe7\xe3o\\nde relat\xf3rios de testes de seguran\xe7a:\\n• testes de intrus\xe3o do Centro Integrado de Seguran\xe7a Cibern\xe9tica (CISC GOV.BR):\\nhttps://www.gov.br/cisc/pt-br\\n• Metodologias de Teste de Intrus\xe3o da OWASP: https://owasp.org/www-project-websecurity-testing-guide/latest/3-The_OWASP_Testing_Framework/1-\\nPenetration_Testing_Methodologies\\n• Conselho de Normas de Seguran\xe7a da Ind\xfastria de Meios de Pagamento (Payment\\nCard Industry Security Standards Council – PCI SSC) – Guia de Testes de Intrus\xe3o:\\nhttps://www.pcisecuritystandards.org/documents/Penetration-Testing-Guidancev1_1.pdf","fique_atento":null,"aplicabilidade_privacidade":""},{"id":21,"nome":"Registro das opera\xe7\xf5es de tratamento de dados pessoais","texto":"Este controle estabelece a necessidade de a organiza\xe7\xe3o elaborar e manter, de forma\\ncont\xednua, o registro das opera\xe7\xf5es de tratamento de dados pessoais, independentemente do\\nmeio utilizado (f\xedsico ou digital). O registro deve descrever detalhadamente o fluxo dos dados\\npessoais, desde a coleta at\xe9 o descarte, contemplando informa\xe7\xf5es como as fontes,\\nfinalidades, hip\xf3teses legais que amparam o tratamento, tempo de reten\xe7\xe3o, solu\xe7\xf5es\\ntecnol\xf3gicas utilizadas, agentes de tratamento envolvidos, compartilhamentos, transfer\xeancias\\ninternacionais.","por_que_implementar":"O registro das opera\xe7\xf5es de tratamento de dados pessoais constitui uma exig\xeancia legal\\nexpressa no artigo 37 da LGPD, sendo considerado o ponto de partida para a governan\xe7a,\\nauditoria e avalia\xe7\xf5es de conformidade dos tratamentos realizados pelo \xf3rg\xe3o.\\nNa aus\xeancia de registros formais, completos e atualizados, a organiza\xe7\xe3o perde a capacidade\\nde demonstrar conformidade, identificar riscos espec\xedficos vinculados aos processos e fluxos\\nde dados pessoais, e atender \xe0s solicita\xe7\xf5es de titulares ou de autoridades fiscalizadoras.\\nAdemais, o registro sistem\xe1tico viabiliza avalia\xe7\xf5es de risco, suporta a elabora\xe7\xe3o de avisos de\\nprivacidade, RIPDs e permite a corre\xe7\xe3o tempestiva de tratamentos em desconformidade \xe0\\nLGPD.","procedimentos_e_ferramentas":"Para a efetiva implementa\xe7\xe3o deste controle, recomenda-se a institui\xe7\xe3o de processo formal,\\ndocumentado e continuamente revisado para o registro e atualiza\xe7\xe3o das opera\xe7\xf5es de\\ntratamento de dados pessoais, com pap\xe9is definidos (por exemplo, respons\xe1vel pelo registro e\\nrevisor) e periodicidade m\xednima de revis\xe3o.\\nRecomenda-se a ado\xe7\xe3o de reposit\xf3rio centralizado que possibilite funcionalidades de busca,\\nversionamento e gera\xe7\xe3o de relat\xf3rios. Ademais, \xe9 recomendada a padroniza\xe7\xe3o dos modelos\\npara registro, abarcando informa\xe7\xf5es essenciais como finalidades, bases legais, tipos e \\ncategorias de dados pessoais e dados pessoais sens\xedveis, fluxos de tratamento e demais\\nelementos necess\xe1rios ao atendimento das exig\xeancias legais e \xe0s necessidades institucionais.","fique_atento":null,"aplicabilidade_privacidade":"Este controle estabelece a necessidade de a organiza\xe7\xe3o elaborar e manter, de forma\\ncont\xednua, o registro das opera\xe7\xf5es de tratamento de dados pessoais, independentemente do\\nmeio utilizado (f\xedsico ou digital). O registro deve descrever detalhadamente o fluxo dos dados\\npessoais, desde a coleta at\xe9 o descarte, contemplando informa\xe7\xf5es como as fontes,\\nfinalidades, hip\xf3teses legais que amparam o tratamento, tempo de reten\xe7\xe3o, solu\xe7\xf5es\\ntecnol\xf3gicas utilizadas, agentes de tratamento envolvidos, compartilhamentos, transfer\xeancias\\ninternacionais."},{"id":22,"nome":"A\xe7\xf5es de preven\xe7\xe3o","texto":"Este controle compreende um conjunto de medidas administrativas voltadas \xe0 mitiga\xe7\xe3o de\\nriscos relacionados ao tratamento de dados pessoais, visando reduzir a probabilidade de\\nviola\xe7\xf5es de privacidade. Abrange, entre outros aspectos, a gest\xe3o de incidentes com dados\\npessoais, a incorpora\xe7\xe3o do princ\xedpio da privacidade desde a concep\xe7\xe3o (privacy by design) e\\no fortalecimento da cultura organizacional em privacidade e prote\xe7\xe3o de dados pessoais por\\nmeio de a\xe7\xf5es de conscientiza\xe7\xe3o e capacita\xe7\xe3o cont\xednuas.","por_que_implementar":"A implementa\xe7\xe3o de medidas preventivas reduz a necessidade de ado\xe7\xe3o de a\xe7\xf5es corretivas\\nposteriores, diminui custos operacionais e refor\xe7a a confian\xe7a de titulares e terceiros em\\nrela\xe7\xe3o ao tratamento de dados pessoais conduzido pela organiza\xe7\xe3o. Ademais, essas\\nmedidas s\xe3o exigidas por orienta\xe7\xf5es e resolu\xe7\xf5es emanadas pela ANPD, compondo requisito\\nfundamental de conformidade. Destaca-se a relev\xe2ncia das iniciativas de conscientiza\xe7\xe3o, que\\npossibilitam o entendimento e a aplica\xe7\xe3o de pr\xe1ticas seguras por todos os agentes p\xfablicos,\\nmitigando, de forma proativa, riscos de incidentes como vazamentos de dados e ataques\\ncibern\xe9ticos.","procedimentos_e_ferramentas":"A efetividade deste controle pressup\xf5e a institui\xe7\xe3o de processos formais e sistematizados que\\nintegrem o requisito de privacidade em todas as iniciativas da organiza\xe7\xe3o – abrangendo\\nprojetos, contrata\xe7\xf5es, novos processos, entre outros.\\nPara concretizar a conformidade \xe0 LGPD e efetivar a prote\xe7\xe3o dos dados pessoais sob a\\nresponsabilidade da organiza\xe7\xe3o, recomenda-se o desenvolvimento cont\xednuo da\\nconscientiza\xe7\xe3o dos agentes p\xfablicos, por meio de a\xe7\xf5es peri\xf3dicas, campanhas informativas,\\nplataformas educacionais, webin\xe1rios, materiais de divulga\xe7\xe3o tem\xe1tica e quizzes interativos. O\\nprograma de conscientiza\xe7\xe3o em prote\xe7\xe3o de dados pessoais pode estar associado ao\\nprograma de conscientiza\xe7\xe3o em seguran\xe7a da informa\xe7\xe3o estabelecido pelo controle 14.\\nMedidas voltadas \xe0 avalia\xe7\xe3o peri\xf3dica do conhecimento dos agentes p\xfablicos e \xe0 integra\xe7\xe3o\\nde conte\xfados de prote\xe7\xe3o de dados pessoais nos programas de forma\xe7\xe3o inicial e continuada\\ns\xe3o fundamentais. \xc9 igualmente recomendada a disponibiliza\xe7\xe3o de canais internos para \\ncontato com o Encarregado pelo tratamento de dados pessoais (medida 21.5) para prestar\\nesclarecimentos e orienta\xe7\xf5es relacionadas \xe0 LGPD e \xe0s pr\xe1ticas seguras.\\nPor fim, sugere-se a elabora\xe7\xe3o de programas de capacita\xe7\xe3o espec\xedficos, adequados ao perfil\\ne \xe0s atribui\xe7\xf5es de cada agente p\xfablico, especialmente considerando a sua atua\xe7\xe3o nas a\xe7\xf5es\\nde conformidade, e assegurando a atualiza\xe7\xe3o constante dos conte\xfados e a ader\xeancia dos\\ntreinamentos \xe0 legisla\xe7\xe3o e \xe0s resolu\xe7\xf5es da ANPD vigentes.\\nPara uma abordagem mais abrangente deste t\xf3pico, considerar os seguintes recursos:\\n• materiais educativos disponibilizados pelo Centro de Excel\xeancia em Privacidade e\\nSeguran\xe7a (CEPS GOV.BR): https://www.gov.br/governodigital/pt-br/privacidade-eseguranca/centro-de-excelencia-em-privacidade-e-seguranca\\n• NIST\xae SP 800-50 - Construindo um Programa de Aprendizagem em Seguran\xe7a\\nCibern\xe9tica e Privacidade: https://csrc.nist.gov/pubs/sp/800/50/r1/final","fique_atento":null,"aplicabilidade_privacidade":"Este controle compreende um conjunto de medidas administrativas voltadas \xe0 mitiga\xe7\xe3o de\\nriscos relacionados ao tratamento de dados pessoais, visando reduzir a probabilidade de\\nviola\xe7\xf5es de privacidade. Abrange, entre outros aspectos, a gest\xe3o de incidentes com dados\\npessoais, a incorpora\xe7\xe3o do princ\xedpio da privacidade desde a concep\xe7\xe3o (privacy by design) e\\no fortalecimento da cultura organizacional em privacidade e prote\xe7\xe3o de dados pessoais por\\nmeio de a\xe7\xf5es de conscientiza\xe7\xe3o e capacita\xe7\xe3o cont\xednuas."},{"id":23,"nome":"Encarregado e direitos dos titulares","texto":"Este controle tem por objetivo estabelecer medidas que assegurem condi\xe7\xf5es adequadas para\\na atua\xe7\xe3o do Encarregado pelo tratamento de dados pessoais, bem como aperfei\xe7oar demais\\nmecanismos organizacionais para assegurar o exerc\xedcio efetivo dos direitos dos titulares. Incluise, nesse \xe2mbito, a implementa\xe7\xe3o de canais de atendimento acess\xedveis e o desenvolvimento\\nde processos claros para tratamento de solicita\xe7\xf5es, os quais devem ser integrados aos fluxos\\nde diferentes \xe1reas, como tecnologia da informa\xe7\xe3o, seguran\xe7a da informa\xe7\xe3o e jur\xeddico.","por_que_implementar":"A atua\xe7\xe3o do Encarregado e a disponibilidade de canais efetivos de atendimento aos titulares\\ns\xe3o requisitos fundamentais para o cumprimento das obriga\xe7\xf5es previstas na LGPD e na\\nResolu\xe7\xe3o CD/ANPD n\xba 18/2024. Processos bem estruturados e executados possibilitam o\\natendimento tempestivo dos direitos dos titulares, fortalecendo a confian\xe7a na organiza\xe7\xe3o e\\npromovendo a transpar\xeancia e a responsabiliza\xe7\xe3o e presta\xe7\xe3o de contas. A aus\xeancia de\\nmecanismos adequados de resposta compromete o relacionamento com os titulares e pode\\nensejar riscos reputacionais e legais para a organiza\xe7\xe3o.","procedimentos_e_ferramentas":"Para a implementa\xe7\xe3o deste controle, recomenda-se:\\n• criar, divulgar e manter canais de atendimento acess\xedveis, tais como portais\\neletr\xf4nicos, formul\xe1rios digitais ou centrais de atendimento dedicadas, com\\nmecanismos de autentica\xe7\xe3o que assegurem a identifica\xe7\xe3o do titular;\\n• definir fluxos de atendimento alinhados aos prazos legais e \xe0s melhores pr\xe1ticas,\\nmantendo modelos padronizados de resposta, crit\xe9rios de triagem e procedimentos de\\nescalonamento das solicita\xe7\xf5es, conforme as \xe1reas envolvidas (neg\xf3cio, TI, jur\xeddico,\\nouvidoria);\\n• assegurar a documenta\xe7\xe3o e rastreabilidade das solicita\xe7\xf5es – utilizando, por exemplo,\\nsistemas de ticketing integrados aos registros das opera\xe7\xf5es de tratamento de dados\\npessoais (controle 19) – e desenvolver relat\xf3rios de desempenho;\\n• estabelecer mecanismos de auditoria e avalia\xe7\xe3o cont\xednua dos canais e processos,\\ngarantindo transpar\xeancia, presta\xe7\xe3o de contas e ader\xeancia aos requisitos legais.\\nConsiderar o seguinte material como refer\xeancia para implementa\xe7\xe3o das medidas previstas\\nneste controle:\\n• ANPD – Guia Orientativo - Atua\xe7\xe3o do encarregado pelo tratamento de dados\\npessoais: https://www.gov.br/anpd/pt-br/centrais-de-conteudo/materiais-educativos-epublicacoes/guia_da_atuacao_do_encarregado_anpd.pdf/view","fique_atento":null,"aplicabilidade_privacidade":"Este controle tem por objetivo estabelecer medidas que assegurem condi\xe7\xf5es adequadas para\\na atua\xe7\xe3o do Encarregado pelo tratamento de dados pessoais, bem como aperfei\xe7oar demais\\nmecanismos organizacionais para assegurar o exerc\xedcio efetivo dos direitos dos titulares. Incluise, nesse \xe2mbito, a implementa\xe7\xe3o de canais de atendimento acess\xedveis e o desenvolvimento\\nde processos claros para tratamento de solicita\xe7\xf5es, os quais devem ser integrados aos fluxos\\nde diferentes \xe1reas, como tecnologia da informa\xe7\xe3o, seguran\xe7a da informa\xe7\xe3o e jur\xeddico."},{"id":24,"nome":"Contratos, acordos e instrumentos cong\xeaneres","texto":"Este controle visa assegurar a incorpora\xe7\xe3o de cl\xe1usulas contratuais, requisitos e pr\xe1ticas\\neficazes que garantam a prote\xe7\xe3o dos dados pessoais nas rela\xe7\xf5es mantidas com terceiros,\\ntais como fornecedores, parceiros, prestadores de servi\xe7o, conv\xeanios e demais agentes de\\ntratamento. Abrange a dilig\xeancia pr\xe9-contratual para avalia\xe7\xe3o da conformidade e capacidade\\nt\xe9cnica dos agentes, a inclus\xe3o de cl\xe1usulas m\xednimas obrigat\xf3rias relativas \xe0 prote\xe7\xe3o de\\ndados pessoais e procedimentos para o acompanhamento do cumprimento contratual.","por_que_implementar":"Grande parte dos incidentes envolvendo dados pessoais decorre de falhas ou condutas\\ninadequadas de terceiros contratados pela organiza\xe7\xe3o. Contratos mal elaborados ou a\\naus\xeancia de mecanismos eficazes de fiscaliza\xe7\xe3o aumentam significativamente a exposi\xe7\xe3o\\nlegal, operacional e reputacional do \xf3rg\xe3o. A ado\xe7\xe3o de cl\xe1usulas padronizadas, alinhadas \xe0\\nLGPD e \xe0 Resolu\xe7\xe3o CD/ANPD n\xba 19/2024, contribui para reduzir os riscos, assegurar a\\nresponsabiliza\xe7\xe3o adequada dos agentes no tratamento e facilitar a resposta eficaz a\\nincidentes, especialmente em casos de vazamento ou uso indevido por terceiros.","procedimentos_e_ferramentas":"Para a implementa\xe7\xe3o efetiva deste controle, recomenda-se:\\n• instituir processos que avaliem a capacidade t\xe9cnica, organizacional e de conformidade\\ndos agentes de tratamento antes da formaliza\xe7\xe3o contratual;\\n• incluir cl\xe1usulas contratuais essenciais que detalhem os objetivos do tratamento,\\nobriga\xe7\xf5es de seguran\xe7a da informa\xe7\xe3o, eventuais restri\xe7\xf5es \xe0 subcontrata\xe7\xe3o,\\nprocedimentos para reporte e gest\xe3o de incidentes, medidas administrativas e t\xe9cnicas\\npara prote\xe7\xe3o dos dados pessoais, regras concernentes \xe0 transfer\xeancia internacional,\\nresponsabilidades em rela\xe7\xe3o a demandas dos titulares e cl\xe1usulas de encerramento,\\ndevolu\xe7\xe3o ou destrui\xe7\xe3o segura dos dados pessoais;\\n• manter um reposit\xf3rio e estabelecer revis\xf5es peri\xf3dicas de contratos, conv\xeanios e\\ninstrumentos cong\xeaneres, acompanhadas de auditorias ou relat\xf3rios padronizados\\npara verificar o cumprimento das obriga\xe7\xf5es relativas \xe0 prote\xe7\xe3o de dados pessoais;\\n• padronizar procedimentos de encerramento contratual que assegurem a anonimiza\xe7\xe3o,\\ndevolu\xe7\xe3o ou descarte seguro dos dados pessoais tratados, acompanhados de\\ncomprova\xe7\xe3o documental.","fique_atento":null,"aplicabilidade_privacidade":"Este controle visa assegurar a incorpora\xe7\xe3o de cl\xe1usulas contratuais, requisitos e pr\xe1ticas\\neficazes que garantam a prote\xe7\xe3o dos dados pessoais nas rela\xe7\xf5es mantidas com terceiros,\\ntais como fornecedores, parceiros, prestadores de servi\xe7o, conv\xeanios e demais agentes de\\ntratamento. Abrange a dilig\xeancia pr\xe9-contratual para avalia\xe7\xe3o da conformidade e capacidade\\nt\xe9cnica dos agentes, a inclus\xe3o de cl\xe1usulas m\xednimas obrigat\xf3rias relativas \xe0 prote\xe7\xe3o de\\ndados pessoais e procedimentos para o acompanhamento do cumprimento contratual."},{"id":25,"nome":"An\xe1lise das opera\xe7\xf5es de tratamento","texto":"Este controle consolida pr\xe1ticas sistem\xe1ticas de an\xe1lise de cada opera\xe7\xe3o de tratamento de\\ndados pessoais registrada no controle 19, promovendo a avalia\xe7\xe3o e aplica\xe7\xe3o de medidas de\\nconformidade espec\xedficas sobre as opera\xe7\xf5es de tratamento. Inclui-se, entre as medidas\\nprevistas, a revis\xe3o criteriosa das finalidades declaradas para o tratamento, a ader\xeancia \xe0s\\nhip\xf3teses legais aplic\xe1veis, assim como a elabora\xe7\xe3o de Relat\xf3rios de Impacto \xe0 Prote\xe7\xe3o de\\nDados Pessoais (RIPD) quando aplic\xe1vel.","por_que_implementar":"A ado\xe7\xe3o de an\xe1lises estruturadas possibilita a identifica\xe7\xe3o precoce de riscos potenciais \xe0\\nprivacidade e aos direitos dos titulares, o que viabiliza a ado\xe7\xe3o tempestiva de medidas\\ncompensat\xf3rias ou mitigadoras. Os RIPDs e as avalia\xe7\xf5es formais correspondentes s\xe3o\\nexig\xeancias frequentes das melhores pr\xe1ticas internacionais e das diretrizes da ANPD,\\nespecialmente em cen\xe1rios de alto risco, tais como o tratamento de dados pessoais sens\xedveis,\\no uso de novas tecnologias ou pr\xe1ticas de perfilagem. Tais instrumentos tamb\xe9m fortalecem a\\ndemonstra\xe7\xe3o de responsabiliza\xe7\xe3o e a presta\xe7\xe3o de contas por parte dos agentes de\\ntratamento.","procedimentos_e_ferramentas":"Recomenda-se a defini\xe7\xe3o clara de crit\xe9rios para an\xe1lise das opera\xe7\xf5es de tratamento,\\nincluindo a eventual necessidade de elabora\xe7\xe3o de RIPD, ponderando sobre fatores como\\ntratamento de dados sens\xedveis, volumes expressivos de dados pessoais, decis\xf5es\\nautomatizadas e transfer\xeancias internacionais de dados. Deve-se estabelecer modelos\\npadronizados para o RIPD e designar equipe multidisciplinar respons\xe1vel pela avalia\xe7\xe3o,\\nenvolvendo o encarregado pelo tratamento de dados pessoais e as \xe1reas de privacidade,\\njur\xeddica, seguran\xe7a da informa\xe7\xe3o e neg\xf3cios.\\nOs resultados das an\xe1lises podem ser integrados ao processo de registro estabelecido no\\ncontrole 19, bem como incorporados ao planejamento e implementa\xe7\xe3o das medidas de\\nmitiga\xe7\xe3o de riscos. Ferramentas de apoio podem abranger checklists, sistemas de gest\xe3o de\\nriscos e fluxos de trabalho que assegurem rastreabilidade das decis\xf5es, armazenamento de\\nevid\xeancias e revis\xf5es documentadas.\\nPara a implementa\xe7\xe3o deste controle, recomenda-se o estudo dos seguintes guias orientativos\\nproduzidos pela ANPD:\\n• Guia Orientativo – Tratamento de dados pessoais pelo Poder P\xfablico:\\nhttps://www.gov.br/anpd/pt-br/centrais-de-conteudo/materiais-educativos-epublicacoes/guia_orientativo_tratamento_de_dados_pessoais_pelo_poder_publico\\n• Guia Orientativo – Hip\xf3teses legais de tratamento de dados pessoais – Leg\xedtimo\\nInteresse: https://www.gov.br/anpd/pt-br/centrais-de-conteudo/materiais-educativos-epublicacoes/guia_orientativo_hipoteses_legais_tratamento_de_dados_pessoais_legitim\\no_interesse\\n• Guia Orientativo – Tratamento de dados pessoais para fins acad\xeamicos e para a\\nrealiza\xe7\xe3o de estudos e pesquisas: https://www.gov.br/anpd/pt-br/centrais-deconteudo/materiais-educativos-e-publicacoes/guia-orientativo-tratamento-de-dadospessoais-para-fins-academicos-e-para-a-realizacao-de-estudos-e-pesquisas","fique_atento":null,"aplicabilidade_privacidade":"Este controle consolida pr\xe1ticas sistem\xe1ticas de an\xe1lise de cada opera\xe7\xe3o de tratamento de\\ndados pessoais registrada no controle 19, promovendo a avalia\xe7\xe3o e aplica\xe7\xe3o de medidas de\\nconformidade espec\xedficas sobre as opera\xe7\xf5es de tratamento. Inclui-se, entre as medidas\\nprevistas, a revis\xe3o criteriosa das finalidades declaradas para o tratamento, a ader\xeancia \xe0s\\nhip\xf3teses legais aplic\xe1veis, assim como a elabora\xe7\xe3o de Relat\xf3rios de Impacto \xe0 Prote\xe7\xe3o de\\nDados Pessoais (RIPD) quando aplic\xe1vel."},{"id":26,"nome":"Compartilhamento e transfer\xeancia internacional","texto":"O compartilhamento de dados pessoais com outros agentes de tratamento e as transfer\xeancias\\ninternacionais devem ser submetidas a avalia\xe7\xf5es espec\xedficas sob a \xe9gide da LGPD e normas\\nrelacionadas. A finalidade \xe9 garantir a legalidade dessas opera\xe7\xf5es, considerando as\\nfinalidades do tratamento, as medidas de privacidade e de seguran\xe7a da informa\xe7\xe3o aplic\xe1veis,\\nal\xe9m dos dispositivos legais e normativos espec\xedficos. Incluem-se neste controle a an\xe1lise\\npr\xe9via da adequa\xe7\xe3o, a aplica\xe7\xe3o das cl\xe1usulas-padr\xe3o regulamentares quando cab\xedvel e a\\nexecu\xe7\xe3o de rotinas obrigat\xf3rias de comunica\xe7\xe3o \xe0 ANPD, conforme previsto na legisla\xe7\xe3o.","por_que_implementar":"Compartilhamentos indevidos sem bases legais ou transfer\xeancias internacionais sem garantias\\nsuficientes ampliam consideravelmente os riscos de exposi\xe7\xe3o indevida e de viola\xe7\xe3o dos\\ndireitos dos titulares de dados pessoais. A LGPD e a Resolu\xe7\xe3o CD/ANPD n\xba 19/2024\\nestabelecem requisitos para a realiza\xe7\xe3o dessas opera\xe7\xf5es, incluindo a necessidade de\\ncontroles contratuais e t\xe9cnicos espec\xedficos para assegurar a prote\xe7\xe3o adequada dos dados\\npessoais.","procedimentos_e_ferramentas":"Para cada opera\xe7\xe3o de compartilhamento registrada conforme controle 19, \xe9 imprescind\xedvel\\nrealizar, previamente \xe0 execu\xe7\xe3o da opera\xe7\xe3o, a an\xe1lise jur\xeddica e a avalia\xe7\xe3o dos riscos\\nenvolvidos – assegurando a defini\xe7\xe3o clara da base legal aplic\xe1vel, da compatibilidade com as\\nfinalidades do tratamento e da implementa\xe7\xe3o das medidas de prote\xe7\xe3o necess\xe1rias.\\nNas transfer\xeancias internacionais, deve-se confirmar a conformidade mediante a valida\xe7\xe3o das\\ngarantias adequadas previstas na Resolu\xe7\xe3o CD/ANPD n\xba 19/2024, tais como decis\xe3o de\\nadequa\xe7\xe3o, cl\xe1usulas-padr\xe3o contratuais, regras contratuais espec\xedficas e obriga\xe7\xf5es t\xe9cnicas\\nadicionais. A documenta\xe7\xe3o comprobat\xf3ria e as cl\xe1usulas contratuais que asseguram os\\ndireitos dos titulares e as medidas de seguran\xe7a da informa\xe7\xe3o devem ser mantidas e\\natualizadas.\\nAl\xe9m disso, \xe9 necess\xe1rio instituir procedimentos para a comunica\xe7\xe3o obrigat\xf3ria \xe0 ANPD\\nquando exigido, garantindo o cumprimento das obriga\xe7\xf5es legais.","fique_atento":null,"aplicabilidade_privacidade":"O compartilhamento de dados pessoais com outros agentes de tratamento e as transfer\xeancias\\ninternacionais devem ser submetidas a avalia\xe7\xf5es espec\xedficas sob a \xe9gide da LGPD e normas\\nrelacionadas. A finalidade \xe9 garantir a legalidade dessas opera\xe7\xf5es, considerando as\\nfinalidades do tratamento, as medidas de privacidade e de seguran\xe7a da informa\xe7\xe3o aplic\xe1veis,\\nal\xe9m dos dispositivos legais e normativos espec\xedficos. Incluem-se neste controle a an\xe1lise\\npr\xe9via da adequa\xe7\xe3o, a aplica\xe7\xe3o das cl\xe1usulas-padr\xe3o regulamentares quando cab\xedvel e a\\nexecu\xe7\xe3o de rotinas obrigat\xf3rias de comunica\xe7\xe3o \xe0 ANPD, conforme previsto na legisla\xe7\xe3o."},{"id":27,"nome":"Princ\xedpios da Lei n\xba 13.709/2018","texto":"A LGPD \xe9 considerada uma norma principiol\xf3gica, ou seja, alicer\xe7ada em princ\xedpios que\\nestabelecem diretrizes sobre o tratamento de dados pessoais. Al\xe9m do registro das opera\xe7\xf5es\\nde tratamento de dados pessoais, identifica\xe7\xe3o de hip\xf3teses legais, an\xe1lises espec\xedficas de\\nconformidade do tratamento, incluindo aspectos de compartilhamento e transfer\xeancia\\ninternacional, o tratamento deve observar os princ\xedpios previstos na legisla\xe7\xe3o. Dessa forma, \\neste controle consolida a necessidade de observ\xe2ncia dos princ\xedpios previstos na LGPD como\\npilares fundamentais das pr\xe1ticas organizacionais frente ao tratamento de dados pessoais.","por_que_implementar":"Os princ\xedpios da LGPD s\xe3o norteadores do arcabou\xe7o normativo e interpretativo aplic\xe1vel \xe0\\nprote\xe7\xe3o de dados pessoais no Brasil. Sua aplica\xe7\xe3o transcende o mero formalismo legal,\\ninfluenciando desde o desenho e a implementa\xe7\xe3o dos processos de tratamento at\xe9 as\\ndecis\xf5es relativas \xe0 reten\xe7\xe3o, uso e compartilhamento de dados pessoais. A demonstra\xe7\xe3o de\\nader\xeancia efetiva a esses princ\xedpios mitiga riscos jur\xeddicos e reputacionais, al\xe9m de constituir\\nrefer\xeancia essencial para auditorias internas e externas, contribuindo para maior transpar\xeancia\\ne responsabilidade institucional.","procedimentos_e_ferramentas":"Recomenda-se a integra\xe7\xe3o sistem\xe1tica dos princ\xedpios em todos os instrumentos normativos e\\noperacionais da organiza\xe7\xe3o, incluindo a elabora\xe7\xe3o de avisos de privacidade, pol\xedticas de\\nreten\xe7\xe3o e minimiza\xe7\xe3o de dados pessoais, checklists de conformidade aplicados na an\xe1lise de\\nnovos projetos e crit\xe9rios rigorosos de avalia\xe7\xe3o em RIPDs. Devem ser institu\xeddos mecanismos\\nde monitoramento que auxiliem na valida\xe7\xe3o efetiva da aplica\xe7\xe3o dos princ\xedpios, como\\nindicadores de transpar\xeancia, m\xe9tricas sobre tempo m\xe9dio de atendimento \xe0s solicita\xe7\xf5es dos\\ntitulares e \xedndices de anonimiza\xe7\xe3o. A capacita\xe7\xe3o cont\xednua dos agentes p\xfablicos envolvidos\\nnas atividades de conformidade, com conte\xfados espec\xedficos sobre os princ\xedpios e suas\\naplica\xe7\xf5es pr\xe1ticas, \xe9 igualmente fundamental para assegurar sua ampla dissemina\xe7\xe3o na\\norganiza\xe7\xe3o.","fique_atento":null,"aplicabilidade_privacidade":"A LGPD \xe9 considerada uma norma principiol\xf3gica, ou seja, alicer\xe7ada em princ\xedpios que\\nestabelecem diretrizes sobre o tratamento de dados pessoais. Al\xe9m do registro das opera\xe7\xf5es\\nde tratamento de dados pessoais, identifica\xe7\xe3o de hip\xf3teses legais, an\xe1lises espec\xedficas de\\nconformidade do tratamento, incluindo aspectos de compartilhamento e transfer\xeancia\\ninternacional, o tratamento deve observar os princ\xedpios previstos na legisla\xe7\xe3o. Dessa forma, \\neste controle consolida a necessidade de observ\xe2ncia dos princ\xedpios previstos na LGPD como\\npilares fundamentais das pr\xe1ticas organizacionais frente ao tratamento de dados pessoais."}]}')}}]);